INSERT INTO authors (slug, name, bio_en, bio_es)
VALUES
  ('albert_einstein', 'Albert Einstein', 'German-born theoretical physicist (1879–1955) who revolutionized physics with the theory of relativity and E=mc². Nobel Prize in 1921.', 'Físico teórico (1879–1955) que revolucionó la física con la teoría de la relatividad y E=mc². Premio Nobel en 1921. Huyó de la Alemania nazi y se convirtió en defensor de la paz.'),
  ('ralph_waldo_emerson', 'Ralph Waldo Emerson', 'American essayist and leader of the Transcendentalist movement (1803–1882). ''Self-Reliance'' and ''Nature'' championed individualism and the divinity within every person.', 'Ensayista y líder del movimiento trascendentalista estadounidense (1803–1882). ''Autoconfianza'' y ''Naturaleza'' defendieron el individualismo y la divinidad dentro de cada persona.'),
  ('seneca', 'Seneca', 'Roman Stoic philosopher, statesman, and playwright (4 BC–65 AD). Advisor to Emperor Nero. His ''Letters to Lucilius'' and ''On the Shortness of Life'' remain essential reading on how to live well.', 'Filósofo estoico romano, estadista y dramaturgo (4 a.C.–65 d.C.). Consejero del emperador Nerón. Sus ''Cartas a Lucilio'' y ''Sobre la brevedad de la vida'' son lectura esencial sobre cómo vivir bien.'),
  ('winston_churchill', 'Winston Churchill', 'British Prime Minister (1874–1965) who led Britain through WWII. Nobel Prize in Literature. Known for ''We shall never surrender.''', 'Primer Ministro británico (1874–1965) que lideró a Gran Bretaña durante la Segunda Guerra Mundial. Premio Nobel de Literatura. Conocido por ''Nunca nos rendiremos.'''),
  ('aristotle', 'Aristotle', 'Greek philosopher and polymath (384–322 BC). Studied under Plato, tutored Alexander the Great. Created formal logic, wrote on ethics, politics, biology, and poetics.', 'Filósofo y polímata griego (384–322 a.C.). Estudió con Platón, fue tutor de Alejandro Magno. Creó la lógica formal y escribió sobre ética, política y biología.'),
  ('richard_bach', 'Richard Bach', 'American writer (1936–) known for ''Jonathan Livingston Seagull'', a fable about a seagull seeking perfection in flight. Explores self-discovery and transcendence.', 'Escritor estadounidense (1936–) conocido por ''Juan Salvador Gaviota'' (1970), una fábula sobre la búsqueda de la perfección. Sus obras exploran el autodescubrimiento y la trascendencia.'),
  ('abraham_lincoln', 'Abraham Lincoln', '16th U.S. President (1809–1865). Led the nation through the Civil War and abolished slavery. Self-educated from frontier poverty to greatness.', '16.° Presidente de Estados Unidos (1809–1865). Lideró la nación durante la Guerra Civil y abolió la esclavitud. Autodidacta desde la pobreza hasta convertirse en uno de los mayores líderes de la historia.'),
  ('epictetus', 'Epictetus', 'Born into slavery in Phrygia (c. 50–135 AD), he gained freedom and founded a school of philosophy. His ''Discourses'' and ''Enchiridion'' teach that freedom comes from mastering our reactions.', 'Nacido esclavo en Frigia (c. 50–135 d.C.), obtuvo su libertad y fundó una escuela filosófica. Sus ''Discursos'' y ''Enquiridión'' enseñan que la libertad viene de dominar nuestras reacciones.'),
  ('plato', 'Plato', 'Athenian philosopher (428–348 BC), student of Socrates, teacher of Aristotle. Founded the Academy in Athens. His dialogues shaped Western thought for 2,400 years.', 'Filósofo ateniense (428–348 a.C.), discípulo de Sócrates y maestro de Aristóteles. Fundó la Academia en Atenas. Sus diálogos moldearon el pensamiento occidental por 2.400 años.'),
  ('wayne_dyer', 'Wayne Dyer', 'American self-help author (1940–2015), ''the father of motivation.'' ''Your Erroneous Zones'' sold 100 million copies.', 'Autor y orador motivacional estadounidense (1940–2015), ''el padre de la motivación.'' ''Tus zonas erróneas'' vendió 100 millones de copias.'),
  ('marcus_aurelius', 'Marcus Aurelius', 'Roman Emperor (161–180 AD) and the last of the Five Good Emperors. His private journal ''Meditations'', written during military campaigns, became one of the greatest Stoic texts ever composed.', 'Emperador romano (161–180 d.C.) y último de los Cinco Buenos Emperadores. Su diario privado ''Meditaciones'', escrito durante campañas militares, se convirtió en uno de los mayores textos estoicos jamás escritos.'),
  ('friedrich_nietzsche', 'Friedrich Nietzsche', 'German philosopher (1844–1900) who declared ''God is dead'' and challenged all conventional morality. His concepts of the Übermensch and will to power reshaped modern philosophy.', 'Filósofo alemán (1844–1900) que declaró ''Dios ha muerto'' y desafió toda moralidad convencional. Sus conceptos del Übermensch y la voluntad de poder redefinieron la filosofía moderna.'),
  ('thomas_edison', 'Thomas Edison', 'American inventor (1847–1931) with 1,093 patents. Created the phonograph, practical light bulb, and motion picture camera.', 'Inventor estadounidense (1847–1931) con 1.093 patentes. Creó el fonógrafo, la bombilla práctica y la cámara de cine.'),
  ('woody_allen', 'Woody Allen', 'American filmmaker and comedian (1935–). Over 50 films including ''Annie Hall'' and ''Manhattan''. Known for neurotic humor and existential themes.', 'Cineasta y comediante estadounidense (1935–). Más de 50 películas incluyendo ''Annie Hall'' y ''Manhattan''. Conocido por su humor neurótico y temas existenciales.'),
  ('confucius', 'Confucius', 'Chinese philosopher and teacher (551–479 BC) whose ideas on ethics, family, and governance became the foundation of East Asian civilization for 25 centuries.', 'Filósofo y maestro chino (551–479 a.C.) cuyas ideas sobre ética, familia y gobierno se convirtieron en el fundamento de la civilización de Asia Oriental durante 25 siglos.'),
  ('carl_jung', 'Carl Jung', 'Swiss psychiatrist (1875–1961) who founded analytical psychology. Introduced the collective unconscious, archetypes, and introversion/extraversion.', 'Psiquiatra suizo (1875–1961) que fundó la psicología analítica. Introdujo los conceptos del inconsciente colectivo, los arquetipos y la introversión/extraversión.'),
  ('napoleon_hill', 'Napoleon Hill', 'American self-help author (1883–1970). ''Think and Grow Rich'' based on interviews with 500 millionaires became one of the best-selling books ever.', 'Autor de autoayuda estadounidense (1883–1970). ''Piense y hágase rico'', basado en entrevistas con 500 millonarios, es uno de los libros más vendidos de todos los tiempos.'),
  ('dalai_lama', 'Dalai Lama', 'Tenzin Gyatso (1935–), 14th Dalai Lama, spiritual leader of Tibetan Buddhism. Nobel Peace Prize 1989. Teaches compassion and nonviolence.', 'Tenzin Gyatso (1935–), el 14.° Dalai Lama, líder espiritual del budismo tibetano. Premio Nobel de la Paz en 1989. Enseña compasión, no violencia y diálogo interreligioso.'),
  ('bruce_lee', 'Bruce Lee', 'Martial artist, actor, and philosopher (1940–1973). Founded Jeet Kune Do. ''Be water, my friend'' transcended martial arts to influence all domains.', 'Artista marcial, actor y filósofo (1940–1973). Fundó el Jeet Kune Do. Su filosofía de adaptabilidad (''Sé agua, amigo mío'') trascendió las artes marciales.'),
  ('tony_robbins', 'Tony Robbins', 'American motivational speaker (1960–). Bestselling author of ''Awaken the Giant Within''. Coaches world leaders, athletes, and entrepreneurs.', 'Orador motivacional y coach de vida estadounidense (1960–). Bestsellers ''Despertando al gigante interior'' y ''Poder sin límites''. Asesora a líderes mundiales y atletas.'),
  ('benjamin_franklin', 'Benjamin Franklin', 'American polymath and Founding Father (1706–1790). Scientist, inventor, diplomat. Discovered electricity''s nature, invented the lightning rod.', 'Polímata estadounidense y Padre Fundador (1706–1790). Científico, inventor y diplomático. Descubrió la naturaleza de la electricidad e inventó el pararrayos.'),
  ('oscar_wilde', 'Oscar Wilde', 'Irish poet and playwright (1854–1900). ''The Picture of Dorian Gray'' and ''The Importance of Being Earnest''. Imprisoned, wrote ''De Profundis.''', 'Poeta y dramaturgo irlandés (1854–1900). Autor de ''El retrato de Dorian Gray'' y ''La importancia de llamarse Ernesto''. Encarcelado, escribió ''De Profundis''.'),
  ('henry_david_thoreau', 'Henry David Thoreau', 'American naturalist (1817–1862). Lived at Walden Pond for two years. ''Walden'' and ''Civil Disobedience'' inspired Gandhi and MLK.', 'Naturalista y filósofo estadounidense (1817–1862). Vivió solo en Walden Pond dos años. ''Walden'' y ''Desobediencia civil'' inspiraron a Gandhi y Martin Luther King Jr.'),
  ('mark_twain', 'Mark Twain', 'American writer (1835–1910), born Samuel Clemens. ''Adventures of Huckleberry Finn''. Called ''the father of American literature.''', 'Escritor y humorista estadounidense (1835–1910). Autor de ''Las aventuras de Huckleberry Finn''. William Faulkner lo llamó ''el padre de la literatura estadounidense.'''),
  ('maya_angelou', 'Maya Angelou', 'American poet and civil rights activist (1928–2014). ''I Know Why the Caged Bird Sings'' broke literary ground.', 'Poetisa, memorialista y activista estadounidense (1928–2014). ''Yo sé por qué canta el pájaro enjaulado'' rompió barreras literarias.'),
  ('socrates', 'Socrates', 'Athenian philosopher (470–399 BC) who wrote nothing but changed everything. His method of relentless questioning exposed contradictions in people''s beliefs.', 'Filósofo ateniense (470–399 a.C.) que no escribió nada pero lo cambió todo. Su método de interrogación incesante exponía las contradicciones en las creencias de la gente.'),
  ('blaise_pascal', 'Blaise Pascal', 'French mathematician and philosopher (1623–1662). Invented the first mechanical calculator. ''Pensées'' explored faith and the human condition.', 'Matemático, físico y filósofo francés (1623–1662). Inventó la primera calculadora mecánica. Sus ''Pensamientos'' exploraron la fe y la condición humana.'),
  ('johann_wolfgang_von_goethe', 'Johann Wolfgang von Goethe', 'German writer and polymath (1749–1832). Author of ''Faust'', the defining work of German literature.', 'Escritor y polímata alemán (1749–1832). Autor de ''Fausto'', la obra definitiva de la literatura alemana. Influyó en el Romanticismo europeo.'),
  ('eleanor_roosevelt', 'Eleanor Roosevelt', 'American activist (1884–1962). Chaired the UN committee that drafted the Universal Declaration of Human Rights.', 'Activista y política estadounidense (1884–1962). Presidió el comité de la ONU que redactó la Declaración Universal de Derechos Humanos.'),
  ('benjamin_disraeli', 'Benjamin Disraeli', 'British PM and novelist (1804–1881). Only British PM who was a novelist before politics.', 'Primer Ministro británico y novelista (1804–1881). El único PM británico que fue novelista publicado antes de entrar en política.'),
  ('og_mandino', 'Og Mandino', 'American author (1923–1996). ''The Greatest Salesman in the World'' sold 50 million copies.', 'Autor estadounidense (1923–1996). Superó el alcoholismo y la pobreza para escribir ''El vendedor más grande del mundo'', que vendió 50 millones de copias.'),
  ('william_shakespeare', 'William Shakespeare', 'English playwright (1564–1616). 37 plays and 154 sonnets that defined the English language.', 'Dramaturgo y poeta inglés (1564–1616). 37 obras y 154 sonetos que definieron el idioma inglés.'),
  ('mother_teresa', 'Mother Teresa', 'Albanian-Indian nun (1910–1997). Founded Missionaries of Charity. Nobel Peace Prize 1979. Canonized 2016.', 'Monja católica albanesa (1910–1997). Fundó las Misioneras de la Caridad en Calcuta. Premio Nobel de la Paz en 1979. Canonizada como santa en 2016.'),
  ('napoleon', 'Napoleon', 'French military leader and Emperor (1769–1821). Rose from Corsican obscurity to conquer most of Europe.', 'Líder militar francés y Emperador (1769–1821). Ascendió de la oscuridad corsa a conquistar la mayor parte de Europa. Su Código Napoleónico reformó sistemas legales en todo el mundo.'),
  ('pablo_picasso', 'Pablo Picasso', 'Spanish painter (1881–1973). Co-founded Cubism. Over 50,000 artworks. The most influential artist of the 20th century.', 'Pintor y escultor español (1881–1973). Cofundó el Cubismo y creó más de 50.000 obras, incluyendo ''Guernica''. El artista más influyente del siglo XX.'),
  ('viktor_frankl', 'Viktor Frankl', 'Austrian psychiatrist and Holocaust survivor (1905–1997). ''Man''s Search for Meaning'' describes finding purpose in Auschwitz.', 'Psiquiatra austríaco y sobreviviente del Holocausto (1905–1997). ''El hombre en busca de sentido'' describe cómo encontrar propósito en Auschwitz. Fundó la logoterapia.'),
  ('mahatma_gandhi', 'Mahatma Gandhi', 'Indian independence leader (1869–1948). Nonviolent resistance freed India from British rule. Inspired civil rights movements worldwide.', 'Líder independentista indio (1869–1948). Desarrolló la resistencia no violenta (satyagraha) que liberó a India del dominio británico.'),
  ('charles_dickens', 'Charles Dickens', 'English novelist (1812–1870). ''Oliver Twist'', ''A Christmas Carol'', ''Great Expectations'' exposed social injustice.', 'Novelista inglés (1812–1870). ''Oliver Twist'', ''Canción de Navidad'', ''Grandes esperanzas'' denunciaron la injusticia social.'),
  ('john_lennon', 'John Lennon', 'English musician and peace activist (1940–1980). Co-founded The Beatles. ''Imagine'' became an anthem for peace.', 'Músico y activista por la paz (1940–1980). Cofundó The Beatles. ''Imagine'' se convirtió en himno de la paz mundial.'),
  ('helen_keller', 'Helen Keller', 'American author (1880–1968). Deaf and blind from 19 months, first deafblind person to earn a bachelor''s degree.', 'Autora y activista estadounidense (1880–1968). Sorda y ciega desde los 19 meses, fue la primera persona sordociega en obtener un título universitario.'),
  ('epicurus', 'Epicurus', 'Greek philosopher (341–270 BC) who taught that pleasure, friendship, and contemplation are the highest good.', 'Filósofo griego (341–270 a.C.) que enseñó que el placer, la amistad y la contemplación intelectual son el bien supremo, y que la muerte no es nada que temer.'),
  ('bertrand_russell', 'Bertrand Russell', 'British philosopher and Nobel laureate (1872–1970). ''Principia Mathematica''. Campaigned for nuclear disarmament.', 'Filósofo y Nobel británico (1872–1970). Coautor de ''Principia Mathematica''. Activista por el desarme nuclear y las libertades civiles.'),
  ('jean_paul_sartre', 'Jean-Paul Sartre', 'French existentialist (1905–1980). ''Existence precedes essence.'' Declined the Nobel Prize. ''Being and Nothingness.''', 'Filósofo existencialista francés (1905–1980). ''La existencia precede a la esencia.'' Rechazó el Nobel. Autor de ''El ser y la nada''.'),
  ('oliver_wendell_holmes_jr', 'Oliver Wendell Holmes Jr.', 'American jurist (1841–1935). 30 years on the Supreme Court. Shaped free speech law.', 'Jurista estadounidense (1841–1935). 30 años en la Corte Suprema. Sus opiniones sobre libertad de expresión moldearon el derecho constitucional americano.'),
  ('douglas_adams', 'Douglas Adams', 'English humorist (1952–2001). ''The Hitchhiker''s Guide to the Galaxy.'' Life''s answer: 42.', 'Autor y humorista inglés (1952–2001). Creó ''La guía del autoestopista galáctico'', respondiendo a la pregunta definitiva con ''42''.'),
  ('rumi', 'Rumi', '13th-century Persian poet and Sufi mystic (1207–1273). 800 years later, still one of the world''s best-selling poets.', 'Poeta persa y místico sufí del siglo XIII (1207–1273). Su ''Masnavi'' es llamado ''el Corán en persa''. 800 años después, sigue siendo uno de los poetas más vendidos del mundo.'),
  ('victor_hugo', 'Victor Hugo', 'French novelist (1802–1885). ''Les Misérables'' and ''The Hunchback of Notre-Dame''. Fought for social justice.', 'Novelista, poeta y activista político francés (1802–1885). Autor de ''Los Miserables'' y ''Nuestra Señora de París''. Luchó por la justicia social.'),
  ('antoine_de_saint_exupery', 'Antoine de Saint-Exupéry', 'French aviator and writer (1900–1944). ''The Little Prince'', one of the most translated books in history.', 'Aviador y escritor francés (1900–1944). Autor de ''El Principito'', uno de los libros más traducidos de la historia. Desapareció en un vuelo de reconocimiento.'),
  ('buddha', 'Buddha', 'Siddhartha Gautama (c. 563–483 BC), born a prince in Nepal, renounced wealth to seek enlightenment. His Four Noble Truths offer a practical guide to ending suffering.', 'Siddhartha Gautama (c. 563–483 a.C.), nacido príncipe en Nepal, renunció a su riqueza para buscar la iluminación. Sus Cuatro Nobles Verdades ofrecen una guía práctica para acabar con el sufrimiento.'),
  ('ernest_hemingway', 'Ernest Hemingway', 'American novelist (1899–1961). Nobel Prize. ''The Old Man and the Sea''. His spare prose redefined modern fiction.', 'Novelista y periodista estadounidense (1899–1961). Premio Nobel de Literatura. Su prosa sobria en ''El viejo y el mar'' redefinió la ficción moderna.'),
  ('immanuel_kant', 'Immanuel Kant', 'German philosopher (1724–1804). ''Critique of Pure Reason'' revolutionized philosophy. Never traveled far from home.', 'Filósofo alemán (1724–1804). ''Crítica de la razón pura'' revolucionó la filosofía. Su imperativo categórico sigue siendo central en la ética moderna.'),
  ('william_james', 'William James', 'American philosopher and psychologist (1842–1910). Father of American psychology. ''Pragmatism.''', 'Filósofo y psicólogo estadounidense (1842–1910). Padre de la psicología americana. Sus obras unieron filosofía, ciencia y espiritualidad.'),
  ('sophocles', 'Sophocles', 'Greek tragedian (496–406 BC). ''Oedipus Rex'' and ''Antigone''. Introduced the third actor to Greek theater.', 'Dramaturgo griego (496–406 a.C.). ''Edipo Rey'' y ''Antígona''. Introdujo el tercer actor en el teatro griego.'),
  ('thich_nhat_hanh', 'Thích Nhất Hạnh', 'Vietnamese Buddhist monk (1926–2022). Coined ''engaged Buddhism.'' MLK nominated him for the Nobel Peace Prize.', 'Monje budista vietnamita y activista por la paz (1926–2022). Acuñó el término ''budismo comprometido.'' Martin Luther King Jr. lo nominó al Nobel de la Paz.'),
  ('john_f_kennedy', 'John F. Kennedy', '35th U.S. President (1917–1963). ''Ask not what your country can do for you.'' Assassinated in Dallas.', '35.° Presidente de EE.UU. (1917–1963). ''No preguntes qué puede hacer tu país por ti.'' Asesinado en Dallas. Inspiró a toda una generación.'),
  ('leonardo_da_vinci', 'Leonardo da Vinci', 'Italian polymath (1452–1519). Mona Lisa, The Last Supper. Inventor, scientist, architect. Centuries ahead of his time.', 'Polímata italiano (1452–1519). Pintor de la Mona Lisa y La Última Cena. Inventor, científico, arquitecto y anatomista. Siglos adelantado a su tiempo.'),
  ('albert_schweitzer', 'Albert Schweitzer', 'French-German theologian and physician (1875–1965). Nobel laureate. Built a hospital in Africa.', 'Teólogo, médico y Nobel franco-alemán (1875–1965). Renunció a una carrera musical para construir un hospital en África. Su filosofía: ''reverencia por la vida.'''),
  ('seneca_the_younger', 'Seneca the Younger', 'Roman Stoic philosopher, statesman, and playwright (4 BC–65 AD), also known as Lucius Annaeus Seneca. Advisor to Emperor Nero. His ''Letters to Lucilius'', ''On the Shortness of Life'', and tragedies remain essential reading on how to live with clarity and courage. ''The Younger'' distinguishes him from his father, Seneca the Elder, a rhetorician.', 'Igual que Séneca — filósofo estoico romano (4 a.C.–65 d.C.). ''El Joven'' lo distingue de su padre, Séneca el Viejo, quien fue retórico.'),
  ('voltaire', 'Voltaire', 'French Enlightenment writer (1694–1778). Champion of free speech. ''Candide'' mocked philosophical optimism.', 'Escritor y filósofo francés de la Ilustración (1694–1778). Defensor de la libertad de expresión. Su novela satírica ''Cándido'' se burló del optimismo filosófico.'),
  ('brian_tracy', 'Brian Tracy', 'Canadian-American motivational speaker and author (1944–). ''Eat That Frog!'' and ''Maximum Achievement.'' Has trained over 5 million people worldwide.', 'Orador motivacional y autor canadiense-estadounidense (1944–). ''¡Tráguese ese sapo!'' y ''Logro máximo.'' Ha formado a más de 5 millones de personas en todo el mundo.'),
  ('franklin_d_roosevelt', 'Franklin D. Roosevelt', '32nd U.S. President (1882–1945). Led through Depression and WWII. Only president elected four times.', '32.° Presidente de EE.UU. (1882–1945). Lideró a América durante la Gran Depresión y la Segunda Guerra Mundial. Único presidente elegido cuatro veces.'),
  ('oprah_winfrey', 'Oprah Winfrey', 'American media mogul (1954–). Rose from poverty to become the most influential woman in media.', 'Magnate de medios y filántropa estadounidense (1954–). Ascendió de la pobreza rural para convertirse en la mujer más influyente de los medios.'),
  ('thomas_carlyle', 'Thomas Carlyle', 'Scottish philosopher (1795–1881). His ''Great Man'' theory argued heroes shape the world.', 'Filósofo e historiador escocés (1795–1881). Su teoría del ''Gran Hombre'' argumentaba que los héroes moldean el mundo.'),
  ('heraclitus', 'Heraclitus', 'Greek philosopher (c. 535–475 BC). ''No man steps in the same river twice.'' Everything flows.', 'Filósofo griego (c. 535–475 a.C.) de Éfeso. ''Nadie se baña dos veces en el mismo río.'' Todo fluye (panta rhei). Creía que el fuego era el elemento fundamental.'),
  ('rene_descartes', 'René Descartes', 'French philosopher (1596–1650). ''I think, therefore I am.'' Founded modern rationalism.', 'Filósofo y matemático francés (1596–1650). ''Pienso, luego existo'' es la frase más famosa de la filosofía. Fundó el racionalismo moderno.'),
  ('coco_chanel', 'Coco Chanel', 'French fashion designer (1883–1971). Created the little black dress, Chanel No. 5, and casual elegance.', 'Diseñadora de moda francesa (1883–1971). Fundó la Casa Chanel y revolucionó la moda femenina. Creó el vestidito negro, Chanel N.° 5 y la elegancia casual.'),
  ('ludwig_wittgenstein', 'Ludwig Wittgenstein', 'Austrian-British philosopher (1889–1951). ''Tractatus'' and ''Philosophical Investigations.'' Gave away his inheritance.', 'Filósofo austro-británico (1889–1951). Su ''Tractatus'' y sus ''Investigaciones filosóficas'' están entre las obras más importantes del siglo XX.'),
  ('theodore_roosevelt', 'Theodore Roosevelt', '26th U.S. President (1858–1919). Youngest president ever. Survived an assassination attempt mid-speech.', '26.° Presidente de EE.UU. (1858–1919). El presidente más joven de la historia. Sobrevivió a un intento de asesinato y terminó su discurso con la bala aún en el pecho.'),
  ('eckhart_tolle', 'Eckhart Tolle', 'German-born spiritual teacher (1948–). ''The Power of Now'' sold millions. Teaches presence and transcending the ego.', 'Maestro espiritual nacido en Alemania (1948–). ''El poder del ahora'' vendió millones y fue traducido a 52 idiomas. Enseña presencia y trascendencia del ego.'),
  ('vince_lombardi', 'Vince Lombardi', 'American football coach (1913–1970). The Super Bowl trophy bears his name.', 'Entrenador de fútbol americano (1913–1970). Llevó a los Packers a cinco campeonatos de la NFL. El trofeo del Super Bowl lleva su nombre.'),
  ('soren_kierkegaard', 'Soren Kierkegaard', 'Danish philosopher (1813–1855), father of existentialism. ''Fear and Trembling.'' Explored anxiety and the leap of faith.', 'Filósofo danés (1813–1855), padre del existencialismo. ''Temor y temblor'' exploró la angustia y el salto de fe.'),
  ('nelson_mandela', 'Nelson Mandela', 'South African leader (1918–2013). 27 years imprisoned. Emerged without bitterness. Nobel Peace Prize 1993.', 'Líder antiapartheid sudafricano (1918–2013). Encarcelado 27 años, emergió sin amargura para convertirse en el primer presidente negro de Sudáfrica. Nobel de la Paz en 1993.'),
  ('plutarch', 'Plutarch', 'Greek biographer (c. 46–120 AD). ''Parallel Lives'' influenced Shakespeare and the American Founding Fathers.', 'Biógrafo y ensayista griego (c. 46–120 d.C.). Sus ''Vidas paralelas'' influyeron en Shakespeare y los Padres Fundadores americanos.'),
  ('dale_carnegie', 'Dale Carnegie', 'American writer (1888–1955). ''How to Win Friends and Influence People'' sold 30 million copies.', 'Escritor y conferenciante estadounidense (1888–1955). ''Cómo ganar amigos e influir sobre las personas'' vendió 30 millones de copias.'),
  ('alan_watts', 'Alan Watts', 'British-American philosopher (1915–1973). Brought Zen Buddhism and Taoism to Western audiences.', 'Filósofo británico-estadounidense (1915–1973). Llevó el budismo zen y el taoísmo a audiencias occidentales. ''El camino del Zen'' sigue siendo una introducción clásica.'),
  ('denis_waitley', 'Denis Waitley', 'American motivational speaker and author (1933–). ''The Psychology of Winning'' became one of the best-selling personal development programs ever recorded.', 'Orador motivacional y autor estadounidense (1933–). ''La psicología de ganar'' se convirtió en uno de los programas de desarrollo personal más vendidos jamás grabados.'),
  ('peter_drucker', 'Peter Drucker', 'Austrian-American management consultant (1909–2005). ''The father of modern management.''', 'Consultor de gestión austro-estadounidense (1909–2005). ''El padre de la gestión moderna.'' Inventó la dirección por objetivos.'),
  ('anatole_france', 'Anatole France', 'French novelist and Nobel laureate (1844–1924). Known for ironic, elegant prose.', 'Novelista y Nobel francés (1844–1924). Conocido por su prosa irónica y elegante. Defensor de la justicia social y la libertad intelectual.'),
  ('sun_tzu', 'Sun Tzu', 'Chinese strategist (544–496 BC). ''The Art of War'' now applied to business, sports, and personal development.', 'Estratega militar chino (544–496 a.C.). Autor de ''El arte de la guerra'', cuyos principios se aplican hoy a negocios, deportes y desarrollo personal.'),
  ('daisaku_ikeda', 'Daisaku Ikeda', 'Japanese Buddhist philosopher and author (1928–2023). President of Soka Gakkai International. One of the world''s most prolific peace advocates.', 'Filósofo y autor budista japonés (1928–2023). Presidente de Soka Gakkai Internacional. Uno de los más prolíficos defensores de la paz en el mundo.'),
  ('marie_curie', 'Marie Curie', 'Polish-French physicist (1867–1934). First woman to win a Nobel Prize. Won two — Physics and Chemistry. Discovered radium and polonium.', 'Física y química polaco-francesa (1867–1934). Primera mujer en ganar un Premio Nobel. Ganó dos — Física y Química. Descubrió el radio y el polonio.'),
  ('jim_rohn', 'Jim Rohn', 'American entrepreneur and motivational speaker (1930–2009). Mentored Tony Robbins. ''You are the average of the five people you spend the most time with.''', 'Empresario y orador motivacional estadounidense (1930–2009). Mentor de Tony Robbins. ''Eres el promedio de las cinco personas con las que más tiempo pasas.'''),
  ('ovid', 'Ovid', 'Roman poet (43 BC–17 AD). Author of ''Metamorphoses'', a narrative poem of mythological transformations that influenced Western art for two millennia.', 'Poeta romano (43 a.C.–17 d.C.). Autor de ''Las metamorfosis'', un poema narrativo de transformaciones mitológicas que influyó en el arte occidental durante dos milenios.'),
  ('anais_nin', 'Anaïs Nin', 'French-Cuban-American writer (1903–1977). Pioneered female erotica and published extensive diaries that explored identity, desire, and self-discovery.', 'Escritora franco-cubano-estadounidense (1903–1977). Pionera de la erótica femenina y autora de extensos diarios que exploran la identidad y el autodescubrimiento.'),
  ('steve_jobs', 'Steve Jobs', 'American entrepreneur (1955–2011). Co-founded Apple, revolutionized personal computing, smartphones, and digital music. ''Stay hungry, stay foolish.''', 'Empresario estadounidense (1955–2011). Cofundó Apple y revolucionó la computación personal, los smartphones y la música digital. ''Mantente hambriento, mantente alocado.'''),
  ('lao_tzu', 'Lao Tzu', 'Semi-legendary Chinese philosopher (6th century BC), credited as author of the ''Tao Te Ching''. His philosophy of wu wei (effortless action) shaped Taoism.', 'Filósofo chino semilegendario (siglo VI a.C.), autor del ''Tao Te Ching''. Su filosofía del wu wei (acción sin esfuerzo) y vivir en armonía con el Tao dio forma al taoísmo.'),
  ('stephen_covey', 'Stephen Covey', 'American educator and author (1932–2012). ''The 7 Habits of Highly Effective People'' sold 40 million copies and transformed corporate training.', 'Educador y autor estadounidense (1932–2012). ''Los 7 hábitos de la gente altamente efectiva'' vendió 40 millones de copias y transformó la formación empresarial.'),
  ('zeno_of_citium', 'Zeno of Citium', 'Greek philosopher (c. 334–262 BC). Founded Stoicism in Athens. Taught that virtue is the only true good and emotions can be mastered through reason.', 'Filósofo griego (c. 334–262 a.C.). Fundó el estoicismo en Atenas. Enseñó que la virtud es el único bien verdadero y que las emociones pueden dominarse con la razón.'),
  ('albert_camus', 'Albert Camus', 'French-Algerian philosopher and novelist (1913–1960). Nobel Prize at 44. ''The Stranger'', ''The Plague'', and ''The Myth of Sisyphus'' explore the absurdity of existence.', 'Filósofo y novelista franco-argelino (1913–1960). Premio Nobel de Literatura a los 44 años. ''El extranjero'', ''La peste'' y ''El mito de Sísifo'' exploran el absurdo de la existencia.'),
  ('john_stuart_mill', 'John Stuart Mill', 'British philosopher and economist (1806–1873). Champion of individual liberty. ''On Liberty'' and utilitarianism remain foundational political texts.', 'Filósofo y economista británico (1806–1873). Defensor de la libertad individual. ''Sobre la libertad'' y el utilitarismo siguen siendo textos políticos fundamentales.'),
  ('man_ray', 'Man Ray', 'American visual artist (1890–1976). Pioneer of Dada and Surrealist photography. His rayographs (cameraless photos) redefined what art could be.', 'Artista visual estadounidense (1890–1976). Pionero del dadaísmo y la fotografía surrealista. Sus rayografías (fotos sin cámara) redefinieron lo que el arte podía ser.'),
  ('robert_m_pirsig', 'Robert M. Pirsig', 'American writer and philosopher (1928–2017). ''Zen and the Art of Motorcycle Maintenance'' explored quality, technology, and the examined life.', 'Escritor y filósofo estadounidense (1928–2017). ''El zen y el arte del mantenimiento de la motocicleta'' exploró la calidad, la tecnología y la vida examinada.'),
  ('buckminster_fuller', 'Buckminster Fuller', 'American architect and inventor (1895–1983). Created the geodesic dome. Coined ''Spaceship Earth.'' Visionary of sustainable design.', 'Arquitecto e inventor estadounidense (1895–1983). Creó la cúpula geodésica. Acuñó ''Nave Espacial Tierra''. Visionario del diseño sostenible.'),
  ('henry_ford', 'Henry Ford', 'American industrialist (1863–1947). Founded Ford Motor Company. Made automobiles affordable through the assembly line. Transformed modern manufacturing.', 'Industrial estadounidense (1863–1947). Fundó Ford Motor Company. Hizo los automóviles accesibles gracias a la cadena de montaje. Transformó la manufactura moderna.'),
  ('george_bernard_shaw', 'George Bernard Shaw', 'Irish playwright and Nobel laureate (1856–1950). ''Pygmalion'', ''Man and Superman.'' Only person to win both a Nobel Prize and an Oscar.', 'Dramaturgo y Nobel irlandés (1856–1950). ''Pygmalion'', ''El hombre y el superhombre.'' La única persona en ganar el Nobel y un Óscar.'),
  ('galileo_galilei', 'Galileo Galilei', 'Italian astronomer and physicist (1564–1642). Father of modern science. Confirmed heliocentrism. Persecuted by the Church for his discoveries.', 'Astrónomo y físico italiano (1564–1642). Padre de la ciencia moderna. Confirmó el heliocentrismo. Perseguido por la Iglesia por sus descubrimientos.'),
  ('georg_hegel', 'Georg Hegel', 'German philosopher (1770–1831). Developed dialectical method (thesis-antithesis-synthesis). Influenced Marx, existentialism, and modern political philosophy.', 'Filósofo alemán (1770–1831). Desarrolló el método dialéctico (tesis-antítesis-síntesis). Influyó en Marx, el existencialismo y la filosofía política moderna.'),
  ('c_s_lewis', 'C.S. Lewis', 'British writer (1898–1963). ''The Chronicles of Narnia'' and ''Mere Christianity.'' Atheist-turned-Christian apologist and close friend of Tolkien.', 'Escritor británico (1898–1963). ''Las crónicas de Narnia'' y ''Mero cristianismo.'' Ateo convertido al cristianismo y amigo íntimo de Tolkien.'),
  ('wayne_gretzky', 'Wayne Gretzky', 'Canadian hockey player (1961–). ''The Great One.'' Holds 61 NHL records. ''You miss 100% of the shots you don''t take.''', 'Jugador de hockey canadiense (1961–). ''El Grande.'' Tiene 61 récords de la NHL. ''Fallas el 100% de los tiros que no intentas.'''),
  ('desmond_tutu', 'Desmond Tutu', 'South African Anglican bishop (1931–2021). Nobel Peace Prize 1984. Led the Truth and Reconciliation Commission after apartheid.', 'Obispo anglicano sudafricano (1931–2021). Premio Nobel de la Paz en 1984. Lideró la Comisión de la Verdad y la Reconciliación tras el apartheid.'),
  ('norman_vincent_peale', 'Norman Vincent Peale', 'American minister and author (1898–1993). ''The Power of Positive Thinking'' sold 5 million copies and pioneered the self-help genre.', 'Ministro y autor estadounidense (1898–1993). ''El poder del pensamiento positivo'' vendió 5 millones de copias y fue pionero del género de autoayuda.'),
  ('simone_de_beauvoir', 'Simone de Beauvoir', 'French existentialist philosopher (1908–1986). ''The Second Sex'' became the foundational text of modern feminism.', 'Filósofa existencialista francesa (1908–1986). ''El segundo sexo'' se convirtió en el texto fundacional del feminismo moderno.'),
  ('billie_jean_king', 'Billie Jean King', 'American tennis champion (1943–). Won 39 Grand Slam titles. Beat Bobby Riggs in the ''Battle of the Sexes.'' Pioneered gender equality in sports.', 'Campeona de tenis estadounidense (1943–). 39 títulos de Grand Slam. Derrotó a Bobby Riggs en la ''Batalla de los Sexos''. Pionera de la igualdad de género en el deporte.'),
  ('yogi_berra', 'Yogi Berra', 'American baseball legend (1925–2015). 10 World Series rings. Famous for paradoxical sayings: ''It ain''t over till it''s over.''', 'Leyenda del béisbol estadounidense (1925–2015). 10 anillos de la Serie Mundial. Famoso por sus dichos paradójicos: ''No habrá terminado hasta que termine.'''),
  ('edgar_allan_poe', 'Edgar Allan Poe', 'American writer (1809–1849). Master of gothic horror and detective fiction. ''The Raven'', ''The Tell-Tale Heart.'' Died mysteriously at 40.', 'Escritor estadounidense (1809–1849). Maestro del terror gótico y la ficción detectivesca. ''El cuervo'', ''El corazón delator.'' Murió misteriosamente a los 40 años.'),
  ('george_orwell', 'George Orwell', 'British writer (1903–1950). ''1984'' and ''Animal Farm'' warned against totalitarianism. His name became an adjective: ''Orwellian.''', 'Escritor británico (1903–1950). ''1984'' y ''Rebelión en la granja'' advirtieron contra el totalitarismo. Su nombre se convirtió en adjetivo: ''orwelliano.'''),
  ('pema_chodron', 'Pema Chödrön', 'American Buddhist nun (1936–). Student of Chögyam Trungpa. ''When Things Fall Apart'' teaches embracing uncertainty as a path to awakening.', 'Monja budista estadounidense (1936–). Discípula de Chögyam Trungpa. ''Cuando todo se derrumba'' enseña a abrazar la incertidumbre como camino al despertar.'),
  ('aldous_huxley', 'Aldous Huxley', 'British writer (1894–1963). ''Brave New World'' predicted a society controlled by pleasure, not pain. Also explored mysticism and psychedelics.', 'Escritor británico (1894–1963). ''Un mundo feliz'' predijo una sociedad controlada por el placer, no el dolor. También exploró el misticismo y los psicodélicos.'),
  ('henry_james', 'Henry James', 'American-British novelist (1843–1916). Master of psychological realism. ''The Portrait of a Lady'', ''The Turn of the Screw.''', 'Novelista estadounidense-británico (1843–1916). Maestro del realismo psicológico. ''El retrato de una dama'', ''Otra vuelta de tuerca.'''),
  ('thomas_jefferson', 'Thomas Jefferson', '3rd U.S. President (1743–1826). Principal author of the Declaration of Independence. Founded the University of Virginia.', '3.er Presidente de EE.UU. (1743–1826). Autor principal de la Declaración de Independencia. Fundó la Universidad de Virginia.'),
  ('edith_wharton', 'Edith Wharton', 'American novelist (1862–1937). First woman to win the Pulitzer Prize. ''The Age of Innocence'' depicted New York''s aristocratic society.', 'Novelista estadounidense (1862–1937). Primera mujer en ganar el Premio Pulitzer. ''La edad de la inocencia'' retrató la aristocracia de Nueva York.'),
  ('zhuang_zhou', 'Zhuang Zhou', 'Chinese philosopher (c. 369–286 BC). Key figure in Taoism. His butterfly dream parable questioned the nature of reality itself.', 'Filósofo chino (c. 369–286 a.C.). Figura clave del taoísmo. Su parábola de la mariposa cuestionó la naturaleza de la realidad.'),
  ('george_eliot', 'George Eliot', 'English novelist (1819–1880), born Mary Ann Evans. ''Middlemarch'' is considered one of the greatest novels in the English language.', 'Novelista inglesa (1819–1880), nacida Mary Ann Evans. ''Middlemarch'' es considerada una de las mayores novelas en lengua inglesa.'),
  ('lou_holtz', 'Lou Holtz', 'American football coach (1937–). Led Notre Dame to a national championship. Known for motivational speeches on attitude and commitment.', 'Entrenador de fútbol americano estadounidense (1937–). Llevó a Notre Dame al campeonato nacional. Conocido por discursos motivadores sobre actitud y compromiso.'),
  ('thomas_paine', 'Thomas Paine', 'American-British political activist (1737–1809). ''Common Sense'' ignited the American Revolution. ''The Rights of Man'' defended the French Revolution.', 'Activista político anglo-americano (1737–1809). ''El sentido común'' encendió la Revolución Americana. ''Los derechos del hombre'' defendió la Revolución Francesa.'),
  ('george_s_patton', 'George S. Patton', 'American general (1885–1945). Led the Third Army across Europe in WWII. Known for aggressive tactics and colorful personality.', 'General estadounidense (1885–1945). Lideró el Tercer Ejército a través de Europa en la Segunda Guerra Mundial. Conocido por su agresividad y personalidad colorida.'),
  ('john_dryden', 'John Dryden', 'English poet and critic (1631–1700). First Poet Laureate of England. Dominated the literary scene of the Restoration era.', 'Poeta y crítico inglés (1631–1700). Primer Poeta Laureado de Inglaterra. Dominó la escena literaria de la era de la Restauración.'),
  ('lucille_ball', 'Lucille Ball', 'American actress and comedian (1911–1989). ''I Love Lucy'' pioneered television comedy. First woman to run a major TV production studio.', 'Actriz y comediante estadounidense (1911–1989). ''I Love Lucy'' revolucionó la comedia televisiva. Primera mujer en dirigir un gran estudio de producción de TV.'),
  ('anne_frank', 'Anne Frank', 'German-Dutch Jewish girl (1929–1945). Her diary, written while hiding from Nazis, became one of the most read books in history. Died in Bergen-Belsen.', 'Joven judía alemana-holandesa (1929–1945). Su diario, escrito en la clandestinidad durante el Holocausto, se convirtió en uno de los libros más leídos de la historia.'),
  ('doris_mortman', 'Doris Mortman', 'American novelist known for glamorous thrillers set in the worlds of fashion, publishing, and photography. Her debut ''Circles'' became a bestseller.', 'Novelista estadounidense conocida por sus thrillers glamurosos ambientados en el mundo de la moda, la edición y la fotografía.'),
  ('john_dewey', 'John Dewey', 'American philosopher and educator (1859–1952). Father of progressive education. Believed learning by doing trumps rote memorization. Shaped modern democratic schooling.', 'Filósofo y educador estadounidense (1859–1952). Padre de la educación progresista. Creía que aprender haciendo supera a la memorización. Moldeó la escuela democrática moderna.'),
  ('virgil', 'Virgil', 'Roman poet (70–19 BC). Author of the ''Aeneid'', the epic that defined Roman identity and shaped Western literature for 2,000 years.', 'Poeta romano (70–19 a.C.). Autor de la ''Eneida'', el poema épico que definió la identidad romana y moldeó la literatura occidental durante 2.000 años.'),
  ('william_arthur_ward', 'William Arthur Ward', 'American author (1921–1994). One of America''s most quoted writers of inspirational maxims. His simple, direct aphorisms appeared in Reader''s Digest for decades.', 'Autor estadounidense (1921–1994). Uno de los escritores más citados de máximas inspiracionales de América. Sus aforismos aparecieron en Reader''s Digest durante décadas.'),
  ('mary_kay_ash', 'Mary Kay Ash', 'American businesswoman (1918–2001). Founded Mary Kay Cosmetics in 1963 with $5,000. Built a billion-dollar empire on the principle of praising people to success.', 'Empresaria estadounidense (1918–2001). Fundó Mary Kay Cosmetics en 1963 con 5.000 dólares. Construyó un imperio multimillonario basado en el principio de elogiar a las personas al éxito.'),
  ('sai_baba', 'Sai Baba', 'Shirdi Sai Baba (d. 1918), Indian spiritual master venerated by Hindus and Muslims alike. Taught unity of all religions through service, love, and devotion.', 'Shirdi Sai Baba (m. 1918), maestro espiritual indio venerado por hindúes y musulmanes por igual. Enseñó la unidad de todas las religiones a través del servicio, el amor y la devoción.'),
  ('william_ellery_channing', 'William Ellery Channing', 'American Unitarian minister (1780–1842). Called ''the apostle of Unitarianism.'' His sermons on human dignity influenced Emerson and the Transcendentalist movement.', 'Ministro unitario estadounidense (1780–1842). Llamado ''el apóstol del unitarismo.'' Sus sermones sobre la dignidad humana influyeron en Emerson y el trascendentalismo.'),
  ('dorothy_thompson', 'Dorothy Thompson', 'American journalist (1893–1961). First foreign correspondent expelled from Nazi Germany. Called ''the First Lady of American Journalism.''', 'Periodista estadounidense (1893–1961). Primera corresponsal extranjera expulsada de la Alemania nazi. Llamada ''la Primera Dama del periodismo americano.'''),
  ('robert_louis_stevenson', 'Robert Louis Stevenson', 'Scottish novelist (1850–1894). ''Treasure Island'', ''Kidnapped'', ''Strange Case of Dr Jekyll and Mr Hyde.'' Wrote vivid adventures while fighting tuberculosis.', 'Novelista escocés (1850–1894). ''La isla del tesoro'', ''Secuestrado'', ''El extraño caso del Dr. Jekyll y Mr. Hyde.'' Escribió aventuras vívidas mientras combatía la tuberculosis.'),
  ('zig_ziglar', 'Zig Ziglar', 'American motivational speaker (1926–2012). Bestselling author and coach. Famous for: ''You can have everything in life you want if you help enough other people get what they want.''', 'Orador motivacional estadounidense (1926–2012). Autor y coach de éxito. Famoso por: ''Puedes tener todo lo que quieras en la vida si ayudas suficientes personas a conseguir lo que ellas quieren.'''),
  ('john_wooden', 'John Wooden', 'American basketball coach (1910–2010). Won 10 NCAA championships at UCLA — including seven in a row. ''Success is peace of mind which is a direct result of self-satisfaction.''', 'Entrenador de baloncesto estadounidense (1910–2010). Ganó 10 campeonatos universitarios en UCLA, siete consecutivos. ''El éxito es la paz mental resultado de la satisfacción por haber dado lo mejor de uno mismo.'''),
  ('john_lubbock', 'John Lubbock', 'British banker and naturalist (1834–1913). 1st Baron Avebury. Championed public holidays (''Bank Holidays''). Wrote on prehistoric man and the habits of ants.', 'Banquero y naturalista británico (1834–1913). Primer Barón de Avebury. Impulsó los días festivos públicos (''Bank Holidays''). Escribió sobre el hombre prehistórico y las costumbres de las hormigas.'),
  ('joseph_campbell', 'Joseph Campbell', 'American mythologist (1904–1987). ''The Hero with a Thousand Faces'' revealed the universal story structure. George Lucas credited him as Star Wars'' intellectual father.', 'Mitólogo estadounidense (1904–1987). ''El héroe de las mil caras'' identificó el monomito universal. George Lucas lo reconoció como padre intelectual de Star Wars.'),
  ('miguel_de_cervantes', 'Miguel de Cervantes', 'Spanish novelist (1547–1616). ''Don Quixote'' is the first modern novel and the greatest work in the Spanish language. Written partly while imprisoned.', 'Escritor español (1547–1616). ''Don Quijote'' es considerado la primera novela moderna y la mayor obra de la lengua castellana. Escrita en parte en la cárcel.'),
  ('henry_miller', 'Henry Miller', 'American writer (1891–1980). ''Tropic of Cancer'' was banned for obscenity for decades. His autobiographical novels explored freedom and bohemian life in Paris.', 'Escritor estadounidense (1891–1980). ''Trópico de Cáncer'' rompió tabúes literarios. Sus novelas autobiográficas exploraron la libertad y la vida bohemia en París.'),
  ('aeschylus', 'Aeschylus', 'Greek tragedian (c. 525–456 BC). Father of tragedy. Wrote ''The Oresteia'', the only complete trilogy surviving from ancient Greece.', 'Trágico griego (c. 525–456 a.C.). Padre de la tragedia. Escribió ''La Orestíada'', la única trilogía completa superviviente de la Grecia antigua.'),
  ('haruki_murakami', 'Haruki Murakami', 'Japanese novelist (1949–). ''Norwegian Wood'', ''Kafka on the Shore.'' Blends surrealism with loneliness. One of the most translated living authors.', 'Novelista japonés (1949–). ''Tokio Blues'', ''Kafka en la orilla.'' Mezcla surrealismo con soledad. Uno de los autores vivos más traducidos del mundo.'),
  ('james_russell_lowell', 'James Russell Lowell', 'American Romantic poet and diplomat (1819–1891). First editor of The Atlantic Monthly. U.S. ambassador to Spain and England.', 'Poeta romántico y diplomático estadounidense (1819–1891). Primer editor de The Atlantic Monthly. Embajador de EE.UU. en España e Inglaterra.'),
  ('rabindranath_tagore', 'Rabindranath Tagore', 'Indian poet and Nobel laureate (1861–1941). First non-European to win the Nobel in Literature. Composed the national anthems of India and Bangladesh.', 'Poeta y Nobel indio (1861–1941). Primer no europeo en ganar el Nobel de Literatura. Compuso los himnos nacionales de India y Bangladesh.'),
  ('chrysippus', 'Chrysippus', 'Greek Stoic philosopher (c. 279–206 BC). Third head of the Stoic school. Wrote over 700 works, systematizing Stoic logic and ethics.', 'Filósofo estoico griego (c. 279–206 a.C.). Tercer director de la escuela estoica. Escribió más de 700 obras sistematizando la lógica y ética estoicas.'),
  ('jeremy_bentham', 'Jeremy Bentham', 'British philosopher (1748–1832). Founded utilitarianism: ''the greatest happiness of the greatest number.'' His body is still displayed at University College London.', 'Filósofo británico (1748–1832). Fundó el utilitarismo: ''la mayor felicidad para el mayor número''. Su cuerpo sigue expuesto en el University College de Londres.'),
  ('vidal_sassoon', 'Vidal Sassoon', 'British-American hairdresser and businessman (1928–2012). Revolutionized hairstyling with geometric cuts. ''The only place where success comes before work is in the dictionary.''', 'Peluquero y empresario británico-estadounidense (1928–2012). Revolucionó la peluquería con cortes geométricos. ''El único lugar donde el éxito viene antes que el trabajo es en el diccionario.'''),
  ('joseph_wood_krutch', 'Joseph Wood Krutch', 'American critic and naturalist (1893–1970). Drama critic for The Nation. Later championed desert conservation in the American Southwest.', 'Crítico y naturalista estadounidense (1893–1970). Crítico dramático de The Nation. Más tarde defendió la conservación del desierto del suroeste americano.'),
  ('james_gleick', 'James Gleick', 'American science writer (1954–). ''Chaos: Making a New Science'' brought complexity theory to the general public. Also wrote definitive biographies of Feynman and Newton.', 'Escritor científico estadounidense (1954–). ''Caos: la creación de una ciencia'' acercó la teoría de la complejidad al público general.'),
  ('george_berkeley', 'George Berkeley', 'Irish philosopher (1685–1753). Bishop of Cloyne. ''Esse est percipi'' — to be is to be perceived. His immaterialism argued that matter only exists when perceived.', 'Filósofo irlandés (1685–1753). Obispo de Cloyne. ''Esse est percipi'' — existir es ser percibido. Su inmaterialismo argumentó que la materia solo existe cuando es percibida.'),
  ('baruch_spinoza', 'Baruch Spinoza', 'Dutch philosopher (1632–1677). Excommunicated by his Jewish community for radical ideas. His ''Ethics'' argued God and Nature are one substance.', 'Filósofo holandés (1632–1677). Excomulgado por su comunidad judía por ideas radicales. Su ''Ética'' argumentó que Dios y la Naturaleza son una sola sustancia.'),
  ('werner_heisenberg', 'Werner Heisenberg', 'German physicist (1901–1976). Created the uncertainty principle of quantum mechanics. Nobel Prize 1932. Changed our understanding of reality at the atomic level.', 'Físico alemán (1901–1976). Creó el principio de incertidumbre de la mecánica cuántica. Nobel en 1932. Cambió nuestra comprensión de la realidad atómica.'),
  ('protagoras', 'Protagoras', 'Greek sophist (c. 490–420 BC). ''Man is the measure of all things.'' First professional teacher. Charged fees for instruction and championed relativism.', 'Sofista griego (c. 490–420 a.C.). ''El hombre es la medida de todas las cosas.'' Primer maestro profesional. Cobró honorarios por sus enseñanzas y defendió el relativismo.'),
  ('martin_buber', 'Martin Buber', 'Austrian-Israeli philosopher (1878–1965). ''I and Thou'' explored the sacred nature of relationships. Advocated Jewish-Arab cooperation in Palestine.', 'Filósofo austro-israelí (1878–1965). ''Yo y Tú'' exploró la naturaleza sagrada de las relaciones. Abogó por la cooperación judeo-árabe en Palestina.'),
  ('northrop_frye', 'Northrop Frye', 'Canadian literary critic (1912–1991). ''Anatomy of Criticism'' transformed literary studies. Identified archetypal patterns across all Western literature.', 'Crítico literario canadiense (1912–1991). ''Anatomía de la crítica'' transformó los estudios literarios. Identificó patrones arquetípicos en toda la literatura occidental.'),
  ('john_brunner', 'John Brunner', 'British science fiction author (1934–1995). ''Stand on Zanzibar'' predicted overpopulation with eerie accuracy. Pioneer of the dystopian novel.', 'Autor de ciencia ficción británico (1934–1995). ''En pie sobre Zanzíbar'' predijo la superpoblación con inquietante precisión. Pionero de la novela distópica.'),
  ('stewart_brand', 'Stewart Brand', 'American writer (1938–). Founded the Whole Earth Catalog. Coined ''information wants to be free.'' Environmental thinker and pioneer of the digital commons.', 'Escritor y pensador estadounidense (1938–). Fundó el Whole Earth Catalog. Acuñó ''la información quiere ser libre.'' Pionero del movimiento de bienes comunes digitales.'),
  ('don_delillo', 'Don DeLillo', 'American novelist (1936–). ''White Noise'' and ''Underworld'' explored media, consumerism, and postmodern anxiety. National Book Award winner.', 'Novelista estadounidense (1936–). ''Ruido de fondo'' y ''Submundo'' exploraron el consumismo y la ansiedad posmoderna. Premio Nacional del Libro.'),
  ('clay_shirky', 'Clay Shirky', 'American writer and theorist (1964–). ''Here Comes Everybody'' explained how the internet reshapes social organization. Influential voice on participatory culture.', 'Escritor y teórico estadounidense (1964–). ''Aquí viene todo el mundo'' explicó cómo internet transforma la organización social.'),
  ('larry_niven', 'Larry Niven', 'American science fiction author (1938–). ''Ringworld'' won the Hugo Award. Known for hard SF grounded in physics and the concept of Known Space.', 'Autor de ciencia ficción estadounidense (1938–). ''Mundo Anillo'' ganó el Hugo. Conocido por su ciencia ficción dura basada en la física.'),
  ('arthur_c_clarke', 'Arthur C. Clarke', 'British science fiction writer (1917–2008). ''2001: A Space Odyssey.'' Predicted geostationary satellites. ''Any sufficiently advanced technology is indistinguishable from magic.''', 'Escritor de ciencia ficción británico (1917–2008). ''2001: Una odisea del espacio.'' Predijo los satélites geoestacionarios. ''Toda tecnología suficientemente avanzada es indistinguible de la magia.'''),
  ('sydney_j_harris', 'Sydney J. Harris', 'American journalist (1917–1986). Syndicated columnist for the Chicago Daily News. Known for witty observations on society and human nature.', 'Periodista estadounidense (1917–1986). Columnista del Chicago Daily News. Conocido por sus ingeniosas observaciones sobre la sociedad y la naturaleza humana.'),
  ('simon_mainwaring', 'Simon Mainwaring', 'Australian branding consultant and author. ''We First'' advocates for social capitalism — using business as a force for good.', 'Consultor de marca australiano y autor. ''We First'' aboga por el capitalismo social — usar los negocios como fuerza para el bien.'),
  ('volker_grassmuck', 'Volker Grassmuck', 'German media scholar and free culture activist. Researcher on copyright reform, creative commons, and the political economy of knowledge.', 'Académico alemán de medios y activista de cultura libre. Investigador de reforma del derecho de autor y economía política del conocimiento.'),
  ('elbert_hubbard', 'Elbert Hubbard', 'American writer and publisher (1856–1915). Founded the Roycroft artisan community. ''A Message to Garcia'' sold 40 million copies. Died on the Lusitania.', 'Escritor y editor estadounidense (1856–1915). Fundó la comunidad artesanal Roycroft. ''Un mensaje a García'' vendió 40 millones de copias. Murió en el Lusitania.'),
  ('bill_watterson', 'Bill Watterson', 'American cartoonist (1958–). ''Calvin and Hobbes'' (1985–1995) is considered the greatest comic strip of all time. Famously refused to license his characters.', 'Dibujante estadounidense (1958–). ''Calvin y Hobbes'' (1985–1995) es considerada la mejor tira cómica de todos los tiempos. Rechazó famosamente la comercialización de sus personajes.'),
  ('kurt_vonnegut', 'Kurt Vonnegut', 'American novelist (1922–2007). ''Slaughterhouse-Five'' drew from his experience as a POW in Dresden. Dark humor and humanist philosophy.', 'Novelista estadounidense (1922–2007). ''Matadero Cinco'' nació de su experiencia como prisionero de guerra en Dresde. Humor negro y filosofía humanista.'),
  ('carrie_snow', 'Carrie Snow', 'American stand-up comedian known for sharp, witty observations on relationships and modern life.', 'Comediante de stand-up estadounidense conocida por sus ingeniosas y agudas observaciones sobre las relaciones y la vida moderna.'),
  ('john_cleese', 'John Cleese', 'British comedian and actor (1939–). Co-founded Monty Python. ''Fawlty Towers.'' Wrote and starred in some of the most influential comedy of the 20th century.', 'Comediante y actor británico (1939–). Cofundó Monty Python. ''Fawlty Towers.'' Escribió y protagonizó la comedia más influyente del siglo XX.'),
  ('tom_hodgkinson', 'Tom Hodgkinson', 'British writer (1968–). Founded The Idler magazine. ''How to be Idle'' makes the philosophical case for leisure, sloth, and freedom from busyness.', 'Escritor británico (1968–). Fundó la revista The Idler. ''Cómo ser un vago'' hace el caso filosófico a favor del ocio y la libertad frente al ajetreo.'),
  ('henri_poincare', 'Henri Poincaré', 'French mathematician and physicist (1854–1912). Laid the foundations of chaos theory. ''The last universalist'' — one of the last to master every branch of mathematics.', 'Matemático y físico francés (1854–1912). Sentó las bases de la teoría del caos. ''El último universalista'' — uno de los últimos en dominar todas las ramas de las matemáticas.'),
  ('john_lasseter', 'John Lasseter', 'American animator and director (1957–). Co-founded Pixar. Directed ''Toy Story'', the first fully computer-animated feature film. Revitalized Disney animation.', 'Animador y director estadounidense (1957–). Cofundó Pixar. Dirigió ''Toy Story'', el primer largometraje completamente animado por ordenador. Revitalizó la animación de Disney.'),
  ('cory_doctorow', 'Cory Doctorow', 'Canadian-British writer and activist (1971–). ''Little Brother.'' Fierce advocate for digital rights, open access, and creative commons licensing.', 'Escritor y activista canadiense-británico (1971–). ''Little Brother.'' Férreo defensor de los derechos digitales, el acceso abierto y las licencias Creative Commons.'),
  ('douglas_coupland', 'Douglas Coupland', 'Canadian novelist (1961–). ''Generation X'' named a generation and redefined how fiction addresses consumer culture and postmodern alienation.', 'Novelista canadiense (1961–). ''Generación X'' nombró a toda una generación y redefinió cómo la ficción aborda la cultura de consumo y la alienación posmoderna.'),
  ('laurie_anderson', 'Laurie Anderson', 'American avant-garde artist (1947–). Pioneer of performance art, electronic music, and multimedia. Married Lou Reed. Her ''O Superman'' reached #2 in the UK.', 'Artista de vanguardia estadounidense (1947–). Pionera del arte de performance, la música electrónica y el multimedia. Casada con Lou Reed.'),
  ('libby_larsen', 'Libby Larsen', 'American composer (1950–). One of America''s most frequently performed living composers. Co-founded the American Composers Forum.', 'Compositora estadounidense (1950–). Una de las compositoras vivas más interpretadas de América. Cofundó el American Composers Forum.'),
  ('william_hurt', 'William Hurt', 'American actor (1950–2022). Oscar winner for ''Kiss of the Spider Woman''. Known for intense, intellectual performances across four decades of film.', 'Actor estadounidense (1950–2022). Ganador del Óscar por ''El beso de la mujer araña''. Conocido por sus interpretaciones intensas e intelectuales a lo largo de cuatro décadas de cine.'),
  ('martin_luther_king_jr', 'Martin Luther King Jr.', 'American civil rights leader (1929–1968). ''I Have a Dream.'' Led the nonviolent movement for racial equality. Nobel Peace Prize 1964. Assassinated in Memphis.', 'Líder del movimiento de derechos civiles estadounidense (1929–1968). ''Tengo un sueño.'' Lideró el movimiento no violento por la igualdad racial. Nobel de la Paz en 1964. Asesinado en Memphis.'),
  ('francoise_sagan', 'Françoise Sagan', 'French novelist (1935–2004). ''Bonjour Tristesse'', written at 18, was an international sensation. Her work explored love, ennui, and the French bourgeoisie.', 'Novelista francesa (1935–2004). ''Buenos días, tristeza'', escrita a los 18 años, fue una sensación internacional. Su obra exploró el amor, el tedio y la burguesía francesa.'),
  ('j_r_r_tolkien', 'J.R.R. Tolkien', 'British writer and professor (1892–1973). Created Middle-earth. ''The Lord of the Rings'' and ''The Hobbit'' defined modern fantasy literature.', 'Escritor y profesor británico (1892–1973). Creó la Tierra Media. ''El señor de los anillos'' y ''El hobbit'' definieron la literatura fantástica moderna.'),
  ('ted_williams', 'Ted Williams', 'American baseball player (1918–2002). Last player to bat .400 in a season. Interrupted his career twice to serve as a fighter pilot in WWII and Korea.', 'Jugador de béisbol estadounidense (1918–2002). Último jugador en batear .400 en una temporada. Interrumpió su carrera dos veces para servir como piloto de combate en la Segunda Guerra Mundial y Corea.'),
  ('goi_nasu', 'Goi Nasu', 'Japanese writer known for simple, profound aphorisms about life, nature, and the present moment.', 'Escritor japonés conocido por aforismos simples y profundos sobre la vida, la naturaleza y el momento presente.'),
  ('zora_neale_hurston', 'Zora Neale Hurston', 'American novelist and anthropologist (1891–1960). ''Their Eyes Were Watching God.'' Central figure of the Harlem Renaissance.', 'Novelista y antropóloga estadounidense (1891–1960). ''Sus ojos miraban a Dios.'' Figura central del Renacimiento de Harlem.'),
  ('john_green', 'John Green', 'American author and YouTuber (1977–). ''The Fault in Our Stars'' and ''Looking for Alaska.'' Brings philosophy to young adult readers.', 'Autor y youtuber estadounidense (1977–). ''Bajo la misma estrella'' y ''Buscando a Alaska.'' Acerca la filosofía a los lectores jóvenes.'),
  ('napoleon_bonaparte', 'Napoleon Bonaparte', 'French military leader and Emperor (1769–1821). Rose from Corsican obscurity to conquer most of Europe. His Napoleonic Code reformed legal systems worldwide.', 'Líder militar francés y Emperador (1769–1821). Ascendió de la oscuridad corsa a conquistar la mayor parte de Europa. Su Código Napoleónico reformó sistemas legales en todo el mundo.'),
  ('ian_botham', 'Ian Botham', 'English cricketer (1955–). One of cricket''s greatest all-rounders. Led England''s dramatic 1981 Ashes victory almost single-handedly.', 'Criquetero inglés (1955–). Uno de los mejores todoterrenos del críquet. Lideró la dramática victoria de Inglaterra en la serie Ashes de 1981 casi en solitario.'),
  ('knute_rockne', 'Knute Rockne', 'Norwegian-American football coach (1888–1931). Led Notre Dame to five national championships. His ''Win one for the Gipper'' speech became legend.', 'Entrenador de fútbol americano noruego-estadounidense (1888–1931). Llevó a Notre Dame a cinco campeonatos nacionales. Su discurso ''Gana uno por el Gipper'' es legendario.'),
  ('jimmy_johnson', 'Jimmy Johnson', 'American football coach (1943–). Won two Super Bowls with the Dallas Cowboys. Also won a national championship at the University of Miami.', 'Entrenador de fútbol americano estadounidense (1943–). Ganó dos Super Bowls con los Dallas Cowboys. También ganó un campeonato nacional en la Universidad de Miami.'),
  ('cleanthes', 'Cleanthes', 'Greek Stoic philosopher (c. 330–230 BC). Successor of Zeno of Citium as head of the Stoic school. His ''Hymn to Zeus'' is one of the earliest surviving Stoic texts.', 'Filósofo estoico griego (c. 330–230 a.C.). Sucesor de Zenón de Citio como director de la escuela estoica. Su ''Himno a Zeus'' es uno de los primeros textos estoicos conservados.'),
  ('hank_aaron', 'Hank Aaron', 'American baseball player (1934–2021). Held the home run record (755) for 33 years. Overcame racism throughout his career with dignity and grace.', 'Jugador de béisbol estadounidense (1934–2021). Sostuvo el récord de jonrones (755) durante 33 años. Superó el racismo a lo largo de su carrera con dignidad.'),
  ('jim_bouton', 'Jim Bouton', 'American baseball pitcher and author (1939–2019). ''Ball Four'' blew the lid off professional baseball''s locker-room culture. Changed sports journalism forever.', 'Lanzador de béisbol y autor estadounidense (1939–2019). ''Pelota cuatro'' levantó el velo sobre la cultura del béisbol profesional. Cambió el periodismo deportivo para siempre.'),
  ('rogers_hornsby', 'Rogers Hornsby', 'American baseball player (1896–1963). Career .358 batting average — the highest in National League history. Pure, focused approach to hitting.', 'Jugador de béisbol estadounidense (1896–1963). Promedio de bateo en carrera de .358 — el más alto en la historia de la Liga Nacional.'),
  ('jim_ryun', 'Jim Ryun', 'American middle-distance runner (1947–). First high schooler to run a sub-4-minute mile. Three-time Olympian and later U.S. Congressman.', 'Corredor de media distancia estadounidense (1947–). Primer estudiante de secundaria en correr una milla en menos de 4 minutos. Tres veces olímpico.'),
  ('ernie_banks', 'Ernie Banks', 'American baseball player (1931–2015). ''Mr. Cub.'' Two-time MVP. His famous saying: ''Let''s play two!'' embodied pure love of the game.', 'Jugador de béisbol estadounidense (1931–2015). ''Mr. Cub.'' Dos veces MVP. Su famosa frase: ''¡Juguemos dos!'' encarnaba el amor puro por el juego.'),
  ('sandy_koufax', 'Sandy Koufax', 'American baseball pitcher (1935–). Dominant lefthander for the Dodgers. Retired at 30 due to arthritis after winning three Cy Young Awards.', 'Lanzador de béisbol estadounidense (1935–). Zurdo dominante de los Dodgers. Se retiró a los 30 por artritis tras ganar tres premios Cy Young.'),
  ('carl_lewis', 'Carl Lewis', 'American track and field athlete (1961–). Nine Olympic gold medals. Dominated sprinting and long jump through two decades. Called the ''Athlete of the Century.''', 'Atleta estadounidense (1961–). Nueve medallas de oro olímpicas. Dominó los sprints y el salto de longitud durante dos décadas. Llamado ''Atleta del Siglo.'''),
  ('reggie_jackson_basketball_born_1990', 'Reggie Jackson (basketball, born 1990)', 'American basketball player (1990–). NBA point guard who played for the Pistons and Clippers. Known for clutch performances.', 'Jugador de baloncesto estadounidense (1990–). Base de la NBA que jugó con los Pistons y los Clippers. Conocido por sus actuaciones en momentos clave.'),
  ('robert_griffin_iii', 'Robert Griffin III', 'American football quarterback (1990–). 2011 Heisman Trophy winner. NFL Offensive Rookie of the Year (2012) with the Washington Redskins.', 'Mariscal de campo de fútbol americano estadounidense (1990–). Ganador del Trofeo Heisman en 2011. Mejor Novato Ofensivo de la NFL (2012).'),
  ('joe_adcock', 'Joe Adcock', 'American baseball player (1927–1999). First baseman for the Milwaukee Braves. Hit four home runs and a double in a single game on July 31, 1954.', 'Jugador de béisbol estadounidense (1927–1999). Primera base de los Milwaukee Braves. Bateó cuatro jonrones y un doble en un solo partido el 31 de julio de 1954.'),
  ('mike_singletary_basketball', 'Mike Singletary (basketball)', 'Not to be confused with football player Mike Singletary — a basketball coach and player known for motivational leadership.', 'Entrenador y jugador de baloncesto conocido por su liderazgo motivacional.'),
  ('bob_knight', 'Bob Knight', 'American basketball coach (1940–2023). Won three NCAA championships at Indiana. Winningest coach in Big Ten history. Known for discipline and intensity.', 'Entrenador de baloncesto estadounidense (1940–2023). Ganó tres campeonatos universitarios en Indiana. El entrenador con más victorias en la historia de la Big Ten.'),
  ('woodrow_wilson', 'Woodrow Wilson', '28th U.S. President (1856–1924). Led the U.S. through WWI. Championed the League of Nations (forerunner of the UN), though the Senate rejected U.S. membership.', '28.° Presidente de EE.UU. (1856–1924). Lideró a EE.UU. en la Primera Guerra Mundial. Impulsó la Liga de Naciones, precursora de la ONU.'),
  ('arnold_palmer', 'Arnold Palmer', 'American golfer (1929–2016). One of golf''s all-time greats. ''Arnie''s Army'' of fans followed him everywhere. Made the game accessible to everyday Americans.', 'Golfista estadounidense (1929–2016). Uno de los más grandes del golf. Su ''Ejército de Arnie'' lo seguía a todos lados. Acercó el golf al público general.'),
  ('john_madden', 'John Madden', 'American football coach and broadcaster (1936–2021). Won Super Bowl XI with the Raiders. His video game franchise became the most successful sports game in history.', 'Entrenador de fútbol americano y presentador estadounidense (1936–2021). Ganó el Super Bowl XI con los Raiders. Su videojuego se convirtió en el juego deportivo más exitoso de la historia.'),
  ('michael_phelps', 'Michael Phelps', 'American swimmer (1985–). 23 Olympic gold medals — the most in history. Opened up about mental health struggles after competing.', 'Nadador estadounidense (1985–). 23 medallas de oro olímpicas — el récord en la historia. Habló abiertamente sobre sus luchas con la salud mental.'),
  ('babe_ruth', 'Babe Ruth', 'American baseball player (1895–1948). ''The Sultan of Swat.'' 714 career home runs. Transformed baseball into America''s national pastime.', 'Jugador de béisbol estadounidense (1895–1948). ''El Sultán del Swat.'' 714 jonrones en carrera. Transformó el béisbol en el pasatiempo nacional americano.'),
  ('bob_feller', 'Bob Feller', 'American baseball pitcher (1918–2010). ''Rapid Robert.'' Hall of Famer who voluntarily enlisted the day after Pearl Harbor, sacrificing his prime years to service.', 'Lanzador de béisbol estadounidense (1918–2010). ''Rapid Robert.'' Miembro del Salón de la Fama que se alistó voluntariamente el día después de Pearl Harbor, sacrificando sus años de prime.'),
  ('dan_gable', 'Dan Gable', 'American wrestler and coach (1948–). Olympic gold medalist (1972) without giving up a point. Led Iowa to 15 NCAA championships as coach.', 'Luchador y entrenador estadounidense (1948–). Medalla de oro olímpica en 1972 sin ceder un solo punto. Llevó a Iowa a 15 campeonatos universitarios como entrenador.'),
  ('bobby_unser', 'Bobby Unser', 'American racing driver (1934–2021). Three-time Indianapolis 500 winner. Part of the legendary Unser racing dynasty.', 'Piloto de carreras estadounidense (1934–2021). Tres veces ganador de las 500 Millas de Indianápolis. Parte de la legendaria dinastía de los Unser.'),
  ('kareem_abdul_jabbar', 'Kareem Abdul-Jabbar', 'American basketball player (1947–). Six NBA MVP awards. All-time NBA scoring leader for 38 years. Scholar, author, and civil rights advocate.', 'Jugador de baloncesto estadounidense (1947–). Seis premios MVP de la NBA. Máximo anotador de la NBA durante 38 años. Escritor y activista de derechos civiles.'),
  ('barry_switzer', 'Barry Switzer', 'American football coach (1937–). Won three national championships at Oklahoma and a Super Bowl with the Dallas Cowboys.', 'Entrenador de fútbol americano estadounidense (1937–). Ganó tres campeonatos nacionales en Oklahoma y un Super Bowl con los Dallas Cowboys.'),
  ('jared_diamond', 'Jared Diamond', 'American biologist and author (1937–). ''Guns, Germs, and Steel'' explained why some civilizations conquered others. Pulitzer Prize winner.', 'Biólogo y autor estadounidense (1937–). ''Armas, gérmenes y acero'' explicó por qué unas civilizaciones conquistaron a otras. Premio Pulitzer.'),
  ('arthur_m_schlesinger_jr', 'Arthur M. Schlesinger Jr.', 'American historian (1917–2007). Advisor to President Kennedy. Won two Pulitzer Prizes. His ''The Age of Jackson'' and Kennedy biography are definitive accounts.', 'Historiador estadounidense (1917–2007). Asesor del presidente Kennedy. Ganó dos Premios Pulitzer. Sus trabajos sobre Jackson y Kennedy son relatos definitivos.'),
  ('stephen_chbosky', 'Stephen Chbosky', 'American novelist and filmmaker (1970–). ''The Perks of Being a Wallflower'' became a coming-of-age classic read by millions of teenagers worldwide.', 'Novelista y cineasta estadounidense (1970–). ''Las ventajas de ser invisible'' se convirtió en un clásico de iniciación leído por millones de adolescentes.'),
  ('michael_jordan', 'Michael Jordan', 'American basketball player (1963–). Six NBA championships. Five MVPs. ''I''ve failed over and over again — that is why I succeed.''', 'Jugador de baloncesto estadounidense (1963–). Seis campeonatos de la NBA. Cinco premios MVP. ''He fallado una y otra vez — por eso he triunfado.'''),
  ('mia_hamm', 'Mia Hamm', 'American soccer player (1972–). Two Olympic gold medals, two World Cup titles. First global female soccer superstar. ''The best player in the world'' per Pelé.', 'Jugadora de fútbol estadounidense (1972–). Dos oros olímpicos y dos títulos mundiales. Primera gran superestrella femenina del fútbol mundial.'),
  ('eric_liddell', 'Eric Liddell', 'Scottish sprinter and missionary (1902–1945). Won gold at 1924 Paris Olympics. Refused to run on Sundays for religious reasons. His story told in ''Chariots of Fire.''', 'Velocista y misionero escocés (1902–1945). Ganó el oro en los Juegos Olímpicos de París 1924. Se negó a correr en domingo por convicción religiosa. Su historia se narra en ''Carros de fuego.'''),
  ('p_g_wodehouse', 'P. G. Wodehouse', 'British comic novelist (1881–1975). Created Bertie Wooster and Jeeves, fiction''s greatest comic duo. Wrote over 90 books. Called ''the funniest writer ever'' by many critics.', 'Novelista cómico británico (1881–1975). Creó a Bertie Wooster y Jeeves, el dúo cómico más grande de la ficción. Escribió más de 90 libros.'),
  ('earl_monroe', 'Earl Monroe', 'American basketball player (1944–). ''Black Jesus.'' His playground moves transformed how NBA guards play and how the game is watched.', 'Jugador de baloncesto estadounidense (1944–). ''Black Jesus.'' Sus movimientos callejeros transformaron cómo juegan los bases de la NBA.'),
  ('heywood_broun', 'Heywood Broun', 'American journalist (1888–1939). Columnist for New York World. Helped found the American Newspaper Guild. Known for colorful, passionate prose.', 'Periodista estadounidense (1888–1939). Columnista del New York World. Ayudó a fundar el American Newspaper Guild. Conocido por su prosa apasionada.'),
  ('casey_stengel', 'Casey Stengel', 'American baseball manager (1890–1975). Won seven World Series with the Yankees. Known as ''The Old Professor'' for his tactical genius and colorful speech.', 'Mánager de béisbol estadounidense (1890–1975). Ganó siete Series Mundiales con los Yankees. Conocido como ''El Viejo Profesor'' por su genio táctico.'),
  ('sam_ewing', 'Sam Ewing', 'American humorist and baseball player. Known for witty observations on success, work, and modern life.', 'Humorista y jugador de béisbol estadounidense. Conocido por sus ingeniosas observaciones sobre el éxito, el trabajo y la vida moderna.'),
  ('vernon_cooper', 'Vernon Cooper', 'American preacher and religious figure known for warm, practical wisdom about patience and faith.', 'Predicador y figura religiosa estadounidense conocido por su sabiduría cálida y práctica sobre la paciencia y la fe.'),
  ('nikola_tesla', 'Nikola Tesla', 'Serbian-American inventor (1856–1943). Pioneered alternating current, wireless communication, and the Tesla coil. Visionary genius who died in poverty.', 'Inventor serbio-estadounidense (1856–1943). Pionero de la corriente alterna, la comunicación inalámbrica y la bobina de Tesla. Genio visionario que murió en la pobreza.'),
  ('shaquille_o_neal', 'Shaquille O''Neal', 'American basketball player (1972–). Four NBA championships. Dominant center and global celebrity known for both athletic power and humor.', 'Jugador de baloncesto estadounidense (1972–). Cuatro campeonatos de la NBA. Centro dominante y celebridad mundial conocido por su poderío atlético y su humor.'),
  ('erma_bombeck', 'Erma Bombeck', 'American humorist (1927–1996). Her syndicated column ''At Wit''s End'' reached 30 million readers. Found comedy in the everyday frustrations of suburban motherhood.', 'Humorista estadounidense (1927–1996). Su columna ''At Wit''s End'' llegó a 30 millones de lectores. Encontraba la comedia en las frustraciones cotidianas de la maternidad suburbana.'),
  ('hugo_black', 'Hugo Black', 'American jurist (1886–1971). Associate Justice of the Supreme Court for 34 years. Absolutist defender of the First Amendment. Former member of the Ku Klux Klan who became a civil rights champion.', 'Jurista estadounidense (1886–1971). Juez Asociado del Tribunal Supremo durante 34 años. Defensor absolutista de la Primera Enmienda.'),
  ('muhammad_ali', 'Muhammad Ali', 'American boxer (1942–2016). Three-time heavyweight champion. ''Float like a butterfly, sting like a bee.'' Refused Vietnam draft on principle.', 'Boxeador estadounidense (1942–2016). Tres veces campeón mundial de los pesos pesados. ''Flota como una mariposa, pica como una abeja.'' Se negó al reclutamiento en Vietnam por principios.'),
  ('caterina_fake', 'Caterina Fake', 'American internet entrepreneur (1969–). Co-founded Flickr, the photo-sharing site that shaped the social web. Advocates for human creativity in the digital age.', 'Empresaria de internet estadounidense (1969–). Cofundó Flickr, el sitio de fotos que moldeó la web social. Defiende la creatividad humana en la era digital.'),
  ('charles_lindbergh', 'Charles Lindbergh', 'American aviator (1902–1974). First solo nonstop transatlantic flight (New York to Paris, 1927). His kidnapped infant son became the ''crime of the century.''', 'Aviador estadounidense (1902–1974). Primer vuelo transatlántico en solitario sin escalas (Nueva York a París, 1927).'),
  ('hannah_arendt', 'Hannah Arendt', 'German-American political theorist (1906–1975). Coined ''the banality of evil'' covering the Eichmann trial. ''The Human Condition'' analyzed modern political life.', 'Teórica política alemana-estadounidense (1906–1975). Acuñó ''la banalidad del mal'' cubriendo el juicio de Eichmann. ''La condición humana'' analizó la vida política moderna.'),
  ('parker_palmer', 'Parker Palmer', 'American educator and activist (1939–). ''The Courage to Teach'' transformed teacher education. Advocates for contemplative practice in professional life.', 'Educador y activista estadounidense (1939–). ''El valor de enseñar'' transformó la formación de maestros. Defiende la práctica contemplativa en la vida profesional.'),
  ('fyodor_dostoevsky', 'Fyodor Dostoevsky', 'Russian novelist (1821–1881). ''Crime and Punishment'', ''The Brothers Karamazov.'' Sentenced to death, reprieved.', 'Novelista ruso (1821–1881). Sentenciado a muerte, indultado en el último momento. Escribió ''Crimen y castigo'' y ''Los hermanos Karamázov''.'),
  ('j_paul_getty', 'J. Paul Getty', 'American oil magnate (1892–1976). Once the world''s richest man. Built the Getty Museum. Notoriously refused to pay ransom for his kidnapped grandson.', 'Magnate del petróleo estadounidense (1892–1976). En su tiempo, el hombre más rico del mundo. Construyó el Museo Getty.'),
  ('vernor_vinge', 'Vernor Vinge', 'American science fiction author and mathematician (1944–2019). Coined ''the Singularity'' — the moment AI surpasses human intelligence. ''A Fire Upon the Deep'' won the Hugo.', 'Autor de ciencia ficción y matemático estadounidense (1944–2019). Acuñó ''la Singularidad'' — el momento en que la IA supera la inteligencia humana.'),
  ('b_f_skinner', 'B. F. Skinner', 'American behaviorist psychologist (1904–1990). Father of operant conditioning. ''Behavior of Organisms.'' Believed all behavior is shaped by consequences, not free will.', 'Psicólogo conductista estadounidense (1904–1990). Padre del condicionamiento operante. Creía que toda conducta está moldeada por sus consecuencias.'),
  ('max_frisch', 'Max Frisch', 'Swiss playwright and novelist (1911–1991). ''Homo Faber'' and ''I''m Not Stiller'' explored identity, modernity, and individual freedom. Major voice of 20th-century German literature.', 'Dramaturgo y novelista suizo (1911–1991). ''Homo Faber'' y ''¿Soy Stiller?'' exploraron la identidad y la libertad individual. Gran voz de la literatura alemana del siglo XX.'),
  ('hal_abelson', 'Hal Abelson', 'American computer scientist (1947–). Professor at MIT. Co-creator of Creative Commons. His textbook ''Structure and Interpretation of Computer Programs'' is legendary.', 'Informático estadounidense (1947–). Profesor en el MIT. Cofundador de Creative Commons. Su libro de texto es legendario en la enseñanza de la programación.'),
  ('audrey_hepburn', 'Audrey Hepburn', 'British-Belgian actress and humanitarian (1929–1993). ''Breakfast at Tiffany''s'', ''Roman Holiday.'' UNICEF Goodwill Ambassador. Elegant on screen and off.', 'Actriz y humanitaria británico-belga (1929–1993). ''Desayuno con diamantes'', ''Vacaciones en Roma.'' Embajadora de UNICEF. Elegante dentro y fuera de la pantalla.'),
  ('ursula_k_le_guin', 'Ursula K. Le Guin', 'American science fiction writer (1929–2018). ''The Left Hand of Darkness'' explored gender. ''A Wizard of Earthsea'' defined fantasy. Champion of literary SF.', 'Escritora de ciencia ficción estadounidense (1929–2018). ''La mano izquierda de la oscuridad'' exploró el género. ''Un mago de Terramar'' definió la fantasía literaria.'),
  ('kin_hubbard', 'Kin Hubbard', 'American humorist and caricaturist (1868–1930). Created ''Abe Martin,'' a cracker-barrel philosopher. His sayings anticipated modern stand-up comedy.', 'Humorista y caricaturista estadounidense (1868–1930). Creó a ''Abe Martin'', un filósofo de pueblo. Sus dichos anticiparon el monólogo cómico moderno.'),
  ('fawn_m_brodie', 'Fawn M. Brodie', 'American biographer (1915–1981). ''No Man Knows My History'' (Joseph Smith biography) and ''Thomas Jefferson: An Intimate History.'' Pioneered psychobiography.', 'Biógrafa estadounidense (1915–1981). ''Ningún hombre conoce mi historia'' (biografía de Joseph Smith) y ''Thomas Jefferson: una historia íntima.'' Pionera de la psicobiografía.'),
  ('alan_cohen', 'Alan Cohen', 'American inspirational author and speaker. ''A Deep Breath of Life'' and other works blend spirituality with practical personal growth.', 'Autor y orador inspiracional estadounidense. Sus obras mezclan la espiritualidad con el crecimiento personal práctico.'),
  ('elizabeth_montagu', 'Elizabeth Montagu', 'English writer and society hostess (1718–1800). Leader of the ''Blue Stockings Society.'' ''An Essay on the Writings and Genius of Shakespear'' defended the Bard.', 'Escritora y anfitriona social inglesa (1718–1800). Líder de la ''Sociedad de las Medias Azules.'' Su ensayo sobre Shakespeare defendió al Bardo.'),
  ('gordon_hinckley', 'Gordon Hinckley', 'American religious leader (1910–2008). 15th President of the Church of Jesus Christ of Latter-day Saints. Oversaw enormous global growth of the church.', 'Líder religioso estadounidense (1910–2008). 15.° Presidente de la Iglesia de Jesucristo de los Santos de los Últimos Días. Supervisó un enorme crecimiento mundial de la iglesia.'),
  ('honore_de_balzac', 'Honoré de Balzac', 'French novelist (1799–1850). ''La Comédie humaine'' — 91 novels mapping all of French society. Wrote fueled by 50 cups of coffee a day.', 'Novelista francés (1799–1850). ''La Comedia humana'' — 91 novelas que cartografían toda la sociedad francesa. Escribía impulsado por 50 tazas de café al día.'),
  ('j_m_barrie', 'J. M. Barrie', 'Scottish novelist and playwright (1860–1937). Created Peter Pan, the boy who never grew up. Gave the copyright for Peter Pan to Great Ormond Street Children''s Hospital.', 'Novelista y dramaturgo escocés (1860–1937). Creó a Peter Pan, el niño que nunca creció. Cedió los derechos de Peter Pan al Hospital Great Ormond Street.'),
  ('margaret_fuller', 'Margaret Fuller', 'American journalist and critic (1810–1850). First female foreign war correspondent. ''Woman in the Nineteenth Century'' was the first major American feminist work.', 'Periodista y crítica estadounidense (1810–1850). Primera corresponsal de guerra extranjera femenina. ''La mujer en el siglo XIX'' fue la primera gran obra feminista americana.'),
  ('peter_elbow', 'Peter Elbow', 'American educator (1935–). ''Writing Without Teachers'' revolutionized writing instruction with the freewriting method. Professor at University of Massachusetts Amherst.', 'Educador estadounidense (1935–). ''Escribir sin maestros'' revolucionó la enseñanza de la escritura con el método de escritura libre.'),
  ('anne_bronte', 'Anne Brontë', 'English novelist (1820–1849). The youngest Brontë sister. ''The Tenant of Wildfell Hall'' tackled domestic abuse and alcoholism with radical candor.', 'Novelista inglesa (1820–1849). La menor de las hermanas Brontë. ''La inquilina de Wildfell Hall'' abordó el maltrato doméstico y el alcoholismo con radical franqueza.'),
  ('alexander_chalmers', 'Alexander Chalmers', 'Scottish biographer and editor (1759–1834). Compiled the 32-volume ''General Biographical Dictionary.'' One of the great industrious scholars of his era.', 'Biógrafo y editor escocés (1759–1834). Compiló el ''Diccionario Biográfico General'' de 32 volúmenes. Uno de los grandes eruditos industriosos de su era.'),
  ('h_jackson_brown_jr', 'H. Jackson Brown Jr.', 'American author known for ''Life''s Little Instruction Book'', a collection of wisdom and advice that became a #1 New York Times bestseller.', 'Autor estadounidense conocido por ''Las pequeñas instrucciones para la vida'', colección de sabiduría que fue número 1 en la lista del New York Times.'),
  ('teresa_of_avila', 'Teresa of Ávila', 'Spanish mystic and reformer (1515–1582). Doctor of the Church. Her ''Interior Castle'' mapped the soul''s journey to God through seven mansions of prayer.', 'Mística y reformadora española (1515–1582). Doctora de la Iglesia. Su ''Castillo interior'' trazó el viaje del alma hacia Dios a través de siete mansiones de oración.'),
  ('baltasar_gracian', 'Baltasar Gracián', 'Spanish Jesuit philosopher (1601–1658). ''The Art of Worldly Wisdom'' — 300 maxims on strategy and human nature — is the original self-help book.', 'Filósofo jesuita español (1601–1658). ''El arte de la prudencia'' — 300 máximas sobre estrategia y naturaleza humana — es el libro de autoayuda original.'),
  ('hugh_miller', 'Hugh Miller', 'Scottish geologist and writer (1802–1856). Self-taught stonemason who became a leading scientist. His geology work challenged literal biblical interpretation.', 'Geólogo y escritor escocés (1802–1856). Cantero autodidacta que se convirtió en científico líder. Su obra geológica desafió la interpretación literal de la Biblia.'),
  ('jane_roberts', 'Jane Roberts', 'American author and psychic (1929–1984). Channeled ''Seth'', whose teachings on consciousness and reality influenced the New Age movement.', 'Autora y psíquica estadounidense (1929–1984). Canalizó a ''Seth'', cuyas enseñanzas sobre la conciencia y la realidad influyeron en el movimiento Nueva Era.'),
  ('john_muir', 'John Muir', 'Scottish-American naturalist (1838–1914). Father of the National Parks. His writings saved Yosemite and inspired the modern environmental movement.', 'Naturalista escocés-estadounidense (1838–1914). Padre de los Parques Nacionales. Sus escritos salvaron Yosemite e inspiraron el movimiento medioambiental moderno.'),
  ('leo_tolstoy', 'Leo Tolstoy', 'Russian novelist (1828–1910). ''War and Peace'' and ''Anna Karenina'' are among the greatest novels ever written. Late-life spiritual crisis led to radical pacifism.', 'Novelista ruso (1828–1910). ''Guerra y paz'' y ''Ana Karenina'' figuran entre las mejores novelas jamás escritas. En su madurez adoptó un radical pacifismo espiritual.'),
  ('louis_pasteur', 'Louis Pasteur', 'French chemist and microbiologist (1822–1895). Invented pasteurization and developed vaccines for rabies and anthrax. Saved millions of lives.', 'Químico y microbiólogo francés (1822–1895). Inventó la pasteurización y desarrolló vacunas contra la rabia y el ántrax. Salvó millones de vidas.'),
  ('publilius_syrus', 'Publilius Syrus', 'Roman slave turned mime writer (1st century BC). His collection of moral maxims (''Sententiae'') was used as a school text for centuries.', 'Esclavo romano convertido en mimo y escritor (siglo I a.C.). Su colección de máximas morales (''Sententiae'') fue usada como texto escolar durante siglos.'),
  ('tom_krause', 'Tom Krause', 'American inspirational author and speaker whose words of encouragement and hope have been widely shared worldwide.', 'Autor y orador inspiracional estadounidense cuyas palabras de aliento y esperanza han sido ampliamente compartidas en todo el mundo.'),
  ('calvin_coolidge', 'Calvin Coolidge', '30th U.S. President (1872–1933). ''Silent Cal'' — known for quiet competence and laissez-faire economics during the Roaring Twenties.', '30.° Presidente de EE.UU. (1872–1933). ''El Silencioso Cal'', conocido por su competencia tranquila y la economía del laissez-faire durante los Años Veinte.'),
  ('jonathan_kozol', 'Jonathan Kozol', 'American educator and author (1936–). ''Savage Inequalities'' exposed the stark funding disparities between wealthy and poor American school districts.', 'Educador y autor estadounidense (1936–). ''Desigualdades salvajes'' expuso las enormes diferencias de financiamiento entre las escuelas ricas y pobres de EE.UU.'),
  ('barack_obama', 'Barack Obama', '44th U.S. President (1961–). First African American president. Nobel Peace Prize 2009. Author of ''Dreams from My Father.''', '44.° Presidente de EE.UU. (1961–). Primer presidente afroamericano. Premio Nobel de la Paz en 2009. Autor de ''Los sueños de mi padre.'''),
  ('liberace', 'Liberace', 'American pianist and entertainer (1919–1987). Flamboyant showman who sold out arenas worldwide. Paved the way for theatrical stage performance.', 'Pianista y artista del espectáculo estadounidense (1919–1987). Showman extravagante que llenó estadios en todo el mundo. Pionero del teatro escénico.'),
  ('rabbi_hillel', 'Rabbi Hillel', 'Jewish scholar (c. 110 BC–10 AD). One of the most important figures in Jewish history. ''If not me, who? If not now, when?'' His school shaped the Talmud.', 'Sabio judío (c. 110 a.C.–10 d.C.). Una de las figuras más importantes de la historia judía. ''¿Si no yo, quién? ¿Si no ahora, cuándo?'' Su escuela moldeó el Talmud.'),
  ('benjamin_haydon', 'Benjamin Haydon', 'British painter (1786–1846). Painted enormous historical canvases and mentored Keats and Wordsworth. Died in poverty despite his ambitions.', 'Pintor británico (1786–1846). Pintó enormes lienzos históricos y fue mentor de Keats y Wordsworth. Murió en la pobreza a pesar de sus ambiciones.'),
  ('louise_hay', 'Louise Hay', 'American motivational author (1926–2017). ''You Can Heal Your Life'' sold 50 million copies. Founded Hay House publishing. Pioneer of the affirmations movement.', 'Autora motivacional estadounidense (1926–2017). ''Usted puede sanar su vida'' vendió 50 millones de copias. Fundó Hay House. Pionera del movimiento de afirmaciones.'),
  ('the_buddha', 'The Buddha', 'Siddhartha Gautama (c. 563–483 BC), the awakened one. His teachings on impermanence, suffering, and liberation formed the foundation of Buddhist philosophy.', 'Siddhartha Gautama (c. 563–483 a.C.), el iluminado. Sus enseñanzas sobre la impermanencia, el sufrimiento y la liberación formaron el fundamento de la filosofía budista.'),
  ('sam_levenson', 'Sam Levenson', 'American humorist, teacher, and television host (1911–1980). Known for warm, self-deprecating humor about Jewish family life and immigrant experience.', 'Humorista, maestro y presentador de televisión estadounidense (1911–1980). Conocido por su humor cálido sobre la vida familiar judía y la experiencia inmigrante.'),
  ('niels_bohr', 'Niels Bohr', 'Danish physicist (1885–1962). Nobel Prize for his model of the atom. Key figure in quantum mechanics. Escaped Nazi-occupied Denmark to aid the Allied war effort.', 'Físico danés (1885–1962). Premio Nobel por su modelo del átomo. Figura clave de la mecánica cuántica. Escapó de la Dinamarca ocupada por los nazis.'),
  ('e_m_forster', 'E. M. Forster', 'British novelist (1879–1970). ''A Room with a View'', ''Howards End'', ''A Passage to India.'' Explored class, liberalism, and human connection. ''Only connect.''', 'Novelista británico (1879–1970). ''Habitación con vistas'', ''Howards End'', ''Pasaje a la India.'' Exploró la clase social y la conexión humana. ''Solo conecta.'''),
  ('edmund_burke', 'Edmund Burke', 'Irish-British statesman and philosopher (1729–1797). Father of modern conservatism. ''The only thing necessary for evil to triumph is for good men to do nothing.''', 'Estadista y filósofo irlandés-británico (1729–1797). Padre del conservadurismo moderno. ''Lo único necesario para que el mal triunfe es que los hombres buenos no hagan nada.'''),
  ('harriet_beecher_stowe', 'Harriet Beecher Stowe', 'American author (1811–1896). ''Uncle Tom''s Cabin'' fueled the abolitionist movement. Lincoln reportedly said: ''The little woman who made this great war.''', 'Autora estadounidense (1811–1896). ''La cabaña del tío Tom'' impulsó el movimiento abolicionista.'),
  ('henry_j_kaiser', 'Henry J. Kaiser', 'American industrialist (1882–1967). Built Liberty Ships in WWII at record speed. Founded Kaiser Permanente, pioneering employer-sponsored healthcare.', 'Industrial estadounidense (1882–1967). Construyó barcos Liberty en la Segunda Guerra Mundial a velocidad récord. Fundó Kaiser Permanente, pionero de la sanidad de empresa.'),
  ('john_ruskin', 'John Ruskin', 'English art critic (1819–1900). Champion of J.M.W. Turner and Gothic architecture. ''The Stones of Venice'' remains a masterpiece of cultural criticism.', 'Crítico de arte inglés (1819–1900). Defensor de J.M.W. Turner y la arquitectura gótica. ''Las piedras de Venecia'' sigue siendo una obra maestra de la crítica cultural.'),
  ('kathleen_norris', 'Kathleen Norris', 'American poet and essayist (1947–). ''Dakota: A Spiritual Geography'' and ''The Cloister Walk'' explore faith, landscape, and monastic wisdom.', 'Poetisa y ensayista estadounidense (1947–). ''Dakota: una geografía espiritual'' y ''El claustro walk'' exploran la fe, el paisaje y la sabiduría monástica.'),
  ('samuel_johnson', 'Samuel Johnson', 'English writer (1709–1784). Compiled the first comprehensive English dictionary. His wit and wisdom were captured by biographer James Boswell.', 'Escritor inglés (1709–1784). Compiló el primer diccionario completo de inglés. Su ingenio y sabiduría fueron capturados por su biógrafo James Boswell.'),
  ('audre_lorde', 'Audre Lorde', 'American poet and activist (1934–1992). ''The Master''s Tools Will Never Dismantle the Master''s House.'' Her work intersected race, gender, and sexuality.', 'Poetisa y activista estadounidense (1934–1992). ''Las herramientas del amo nunca desmantelarán la casa del amo.'' Su obra intersectó raza, género y sexualidad.'),
  ('nathaniel_hawthorne', 'Nathaniel Hawthorne', 'American novelist (1804–1864). ''The Scarlet Letter'' explored sin, guilt, and redemption in Puritan New England. Haunted by his ancestors'' role in the Salem witch trials.', 'Novelista estadounidense (1804–1864). ''La letra escarlata'' exploró el pecado, la culpa y la redención en la Nueva Inglaterra puritana.'),
  ('thomas_dewar', 'Thomas Dewar', 'Scottish whisky magnate (1864–1930). Co-built Dewar''s into a global brand. Famous after-dinner speaker whose epigrams were collected and widely published.', 'Magnate escocés del whisky (1864–1930). Construyó Dewar''s como marca global. Sus epigramas fueron recopilados y ampliamente publicados.'),
  ('ambrose_bierce', 'Ambrose Bierce', 'American journalist and satirist (1842–c. 1914). ''The Devil''s Dictionary'' — bitter definitions of human folly. Disappeared mysteriously in Mexico at age 71.', 'Periodista y satírico estadounidense (1842–c. 1914). ''El diccionario del diablo'' — definiciones amargas de la estupidez humana. Desapareció misteriosamente en México a los 71 años.'),
  ('doug_horton', 'Doug Horton', 'American clergyman and educator (1891–1968). Dean of Harvard Divinity School. Known for aphorisms that balance pragmatism with spiritual insight.', 'Clérigo y educador estadounidense (1891–1968). Decano de la Facultad de Teología de Harvard. Conocido por aforismos que equilibran el pragmatismo con la perspectiva espiritual.'),
  ('plotinus', 'Plotinus', 'Egyptian-Roman philosopher (c. 204–270 AD). Founder of Neoplatonism. His ''Enneads'' argued that the soul can return to the divine One through contemplation.', 'Filósofo egipcio-romano (c. 204–270 d.C.). Fundador del neoplatonismo. Sus ''Enéadas'' argumentaron que el alma puede regresar al Uno divino a través de la contemplación.'),
  ('abraham_maslow', 'Abraham Maslow', 'American psychologist (1908–1970). Created the hierarchy of needs. Pioneered humanistic psychology — studying what makes people thrive, not just survive.', 'Psicólogo estadounidense (1908–1970). Creó la jerarquía de necesidades. Pionero de la psicología humanista: estudiar qué hace florecer a las personas.'),
  ('ben_stein', 'Ben Stein', 'American actor, author, and lawyer (1944–). Nixon speechwriter turned game show host (''Win Ben Stein''s Money''). Prolific commentator on economics and culture.', 'Actor, autor y abogado estadounidense (1944–). Orador de Nixon reconvertido en presentador de concursos. Prolífico comentarista sobre economía y cultura.'),
  ('jean_de_la_fontaine', 'Jean de La Fontaine', 'French fabulist (1621–1695). His ''Fables'' — featuring animals acting out human follies — are among the most widely read works of French literature.', 'Fabulista francés (1621–1695). Sus ''Fábulas'' — protagonizadas por animales representando locuras humanas — están entre las obras más leídas de la literatura francesa.'),
  ('laurence_j_peter', 'Laurence J. Peter', 'Canadian educator (1919–1990). Formulated the Peter Principle: ''In a hierarchy, every employee tends to rise to their level of incompetence.''', 'Educador canadiense (1919–1990). Formuló el Principio de Peter: ''En una jerarquía, cada empleado tiende a ascender hasta su nivel de incompetencia.'''),
  ('robert_f_kennedy', 'Robert F. Kennedy', 'American politician (1925–1968). Attorney General, Senator, presidential candidate. Championed civil rights and the poor. Assassinated during his campaign.', 'Político estadounidense (1925–1968). Fiscal General, Senador, candidato presidencial. Defensor de los derechos civiles y los pobres. Asesinado durante su campaña.'),
  ('susan_b_anthony', 'Susan B. Anthony', 'American suffragist (1820–1906). Fought for women''s right to vote for over 50 years. The 19th Amendment was called ''the Susan B. Anthony Amendment.''', 'Sufragista estadounidense (1820–1906). Luchó por el derecho al voto de las mujeres durante más de 50 años. La 19.ª Enmienda fue llamada ''la Enmienda Susan B. Anthony.'''),
  ('thomas_aquinas', 'Thomas Aquinas', 'Italian philosopher and theologian (1225–1274). Combined Aristotelian philosophy with Christian theology. His ''Summa Theologica'' is the intellectual foundation of Catholic thought.', 'Filósofo y teólogo italiano (1225–1274). Combinó la filosofía aristotélica con la teología cristiana. Su ''Suma Teológica'' es el fundamento intelectual del pensamiento católico.'),
  ('alexander_pope', 'Alexander Pope', 'English poet (1688–1744). Master of the heroic couplet. ''Essay on Man'' and ''The Rape of the Lock.'' The most quoted English poet after Shakespeare.', 'Poeta inglés (1688–1744). Maestro del dístico heroico. ''Ensayo sobre el hombre.'' El poeta inglés más citado después de Shakespeare.'),
  ('gustave_flaubert', 'Gustave Flaubert', 'French novelist (1821–1880). ''Madame Bovary'' perfected literary realism. Obsessed with finding ''le mot juste'' — the exact right word.', 'Novelista francés (1821–1880). ''Madame Bovary'' perfeccionó el realismo literario. Obsesionado con encontrar ''le mot juste'' — la palabra exactamente correcta.'),
  ('paul_tillich', 'Paul Tillich', 'German-American theologian (1886–1965). ''The Courage to Be'' explored anxiety and faith. Defined God as ''the ground of being'' rather than a supernatural person.', 'Teólogo alemán-estadounidense (1886–1965). ''El coraje de ser'' exploró la ansiedad y la fe. Definió a Dios como ''el fundamento del ser.'''),
  ('robert_fulghum', 'Robert Fulghum', 'American author and minister (1937–). ''All I Really Need to Know I Learned in Kindergarten'' became an international phenomenon.', 'Autor y ministro estadounidense (1937–). ''Todo lo que realmente necesito saber lo aprendí en el jardín de infantes'' fue un fenómeno internacional.'),
  ('edward_gibbon', 'Edward Gibbon', 'English historian (1737–1794). ''The History of the Decline and Fall of the Roman Empire'' — six volumes spanning 1,500 years — set the standard for historical writing.', 'Historiador inglés (1737–1794). ''Historia de la decadencia y caída del Imperio Romano'' — seis volúmenes abarcando 1.500 años — estableció el estándar de la escritura histórica.'),
  ('euripides', 'Euripides', 'Greek tragedian (c. 480–406 BC). Most modern of ancient dramatists. ''Medea'' and ''The Bacchae'' explored psychology, feminism, and the irrational.', 'Trágico griego (c. 480–406 a.C.). El más moderno de los dramaturgos antiguos. ''Medea'' y ''Las Bacantes'' exploraron la psicología, el feminismo y lo irracional.'),
  ('rainer_maria_rilke', 'Rainer Maria Rilke', 'Austrian poet (1875–1926). ''Letters to a Young Poet'' remains the most beloved guide for aspiring artists. ''Duino Elegies'' reached the heights of lyric poetry.', 'Poeta austríaco (1875–1926). ''Cartas a un joven poeta'' sigue siendo la guía más querida para artistas en ciernes. Las ''Elegías de Duino'' alcanzaron las cimas de la lírica.'),
  ('w_clement_stone', 'W. Clement Stone', 'American businessman and philanthropist (1902–2002). Built Combined Insurance into a fortune. ''Aim for the moon. If you miss, you may hit a star.''', 'Empresario y filántropo estadounidense (1902–2002). Construyó Combined Insurance en una fortuna. ''Apunta a la luna. Si no llegas, puede que alcances una estrella.'''),
  ('rudolf_arnheim', 'Rudolf Arnheim', 'German-American art theorist (1904–2007). ''Art and Visual Perception'' applied Gestalt psychology to understanding visual art. 102 years old at death.', 'Teórico del arte alemán-estadounidense (1904–2007). ''Arte y percepción visual'' aplicó la psicología de la Gestalt al entendimiento del arte visual. Murió a los 102 años.'),
  ('sam_rayburn', 'Sam Rayburn', 'American politician (1882–1961). Served 48 years in Congress and was Speaker of the House three times. ''Any jackass can kick down a barn, but it takes a good carpenter to build one.''', 'Político estadounidense (1882–1961). Sirvió 48 años en el Congreso y fue Presidente de la Cámara tres veces.'),
  ('colin_powell', 'Colin Powell', 'American general and Secretary of State (1937–2021). First African American to hold that office. Rose from the South Bronx to the highest levels of government.', 'General y Secretario de Estado estadounidense (1937–2021). Primer afroamericano en ocupar ese cargo. Ascendió del sur del Bronx a los más altos niveles del gobierno.'),
  ('forrest_church', 'Forrest Church', 'American minister and author (1948–2009). Liberal Unitarian Universalist. ''The Cathedral of the World'' explored religious pluralism and meaning-making.', 'Ministro y autor estadounidense (1948–2009). Unitario liberal. ''La catedral del mundo'' exploró el pluralismo religioso y la construcción de significado.'),
  ('lena_horne', 'Lena Horne', 'American singer and actress (1917–2010). Broke racial barriers in Hollywood. Refused to perform for segregated audiences. Civil rights activist throughout her life.', 'Cantante y actriz estadounidense (1917–2010). Rompió barreras raciales en Hollywood. Activista de derechos civiles de por vida.'),
  ('carl_sandburg', 'Carl Sandburg', 'American poet and biographer (1878–1967). Won three Pulitzer Prizes — two for poetry, one for his Lincoln biography. ''Chicago'' put the Midwest on the literary map.', 'Poeta y biógrafo estadounidense (1878–1967). Ganó tres Premios Pulitzer — dos por poesía, uno por su biografía de Lincoln.'),
  ('margaret_laurence', 'Margaret Laurence', 'Canadian novelist (1926–1987). Her Manawaka cycle — including ''The Stone Angel'' — is the cornerstone of Canadian fiction.', 'Novelista canadiense (1926–1987). Su ciclo de Manawaka — incluyendo ''El ángel de piedra'' — es la piedra angular de la ficción canadiense.'),
  ('a_a_milne', 'A. A. Milne', 'British author (1882–1956). Created Winnie-the-Pooh, the beloved bear of Very Little Brain. His stories carry profound wisdom beneath their gentle humor.', 'Autor británico (1882–1956). Creó a Winnie-the-Pooh, el adorable oso de muy poca sesera. Sus historias llevan una profunda sabiduría bajo su suave humor.'),
  ('betty_friedan', 'Betty Friedan', 'American feminist writer (1921–2006). ''The Feminine Mystique'' ignited second-wave feminism. Co-founded the National Organization for Women.', 'Escritora feminista estadounidense (1921–2006). ''La mística femenina'' encendió el feminismo de segunda ola. Cofundó la Organización Nacional para las Mujeres.'),
  ('cynthia_ozick', 'Cynthia Ozick', 'American novelist and essayist (1928–). One of America''s greatest prose stylists. ''The Shawl'' is a devastating Holocaust novella.', 'Novelista y ensayista estadounidense (1928–). Una de las mayores prosistas de América. ''El chal'' es una devastadora novela corta sobre el Holocausto.'),
  ('francois_de_la_rochefoucauld', 'François de La Rochefoucauld', 'French moralist (1613–1680). His ''Maxims'' — sharp, cynical observations on human nature — influenced La Bruyère, Nietzsche, and modern psychology.', 'Moralista francés (1613–1680). Sus ''Máximas'' — observaciones cínicas y agudas sobre la naturaleza humana — influyeron en Nietzsche y la psicología moderna.'),
  ('henri_bergson', 'Henri Bergson', 'French philosopher and Nobel laureate (1859–1941). Argued that time as lived experience differs from clock time. Influenced Proust and modernist literature.', 'Filósofo y Nobel francés (1859–1941). Argumentó que el tiempo vivido difiere del tiempo del reloj. Influyó en Proust y la literatura modernista.'),
  ('jawaharlal_nehru', 'Jawaharlal Nehru', 'India''s first Prime Minister (1889–1964). Led India through independence. His ''Discovery of India'' explored 5,000 years of civilization.', 'Primer Ministro de India (1889–1964). Lideró India hacia la independencia. Su ''Descubrimiento de India'' exploró 5.000 años de civilización.'),
  ('john_adams', 'John Adams', '2nd U.S. President (1735–1826). Key architect of American independence. Died on the same day as Thomas Jefferson — July 4, 1826.', '2.° Presidente de EE.UU. (1735–1826). Arquitecto clave de la independencia americana. Murió el mismo día que Thomas Jefferson — el 4 de julio de 1826.'),
  ('jonas_salk', 'Jonas Salk', 'American virologist (1914–1995). Developed the first polio vaccine and refused to patent it. ''Could you patent the sun?''', 'Virólogo estadounidense (1914–1995). Desarrolló la primera vacuna contra la polio y se negó a patentarla. ''¿Podrías patentar el sol?'''),
  ('kahlil_gibran', 'Kahlil Gibran', 'Lebanese-American poet and philosopher (1883–1931). ''The Prophet'' has been translated into over 100 languages. Third best-selling poet of all time after Shakespeare and Lao Tzu.', 'Poeta y filósofo libanés-estadounidense (1883–1931). ''El Profeta'' ha sido traducido a más de 100 idiomas. Tercer poeta más vendido de la historia.'),
  ('richard_needham', 'Richard Needham', 'Canadian columnist (1912–1996). Longtime wit of the Toronto Globe and Mail. Known for pointed aphorisms on human nature.', 'Columnista canadiense (1912–1996). Durante años fue el ingenioso colaborador del Toronto Globe and Mail, conocido por sus aforismos sobre la naturaleza humana.'),
  ('shakti_gawain', 'Shakti Gawain', 'American author (1948–2018). ''Creative Visualization'' popularized the use of mental imagery to achieve goals. Pioneer of the New Age self-help genre.', 'Autora estadounidense (1948–2018). ''Visualización creativa'' popularizó el uso de imágenes mentales para lograr metas. Pionera del género de autoayuda Nueva Era.'),
  ('joseph_stalin', 'Joseph Stalin', 'Soviet leader (1878–1953). Ruled the USSR from 1924 until his death. Industrialized the Soviet Union while killing millions through purges and forced labor.', 'Líder soviético (1878–1953). Gobernó la URSS desde 1924 hasta su muerte. Industrializó la Unión Soviética mientras millones morían en purgas y trabajos forzados.'),
  ('wolfgang_amadeus_mozart', 'Wolfgang Amadeus Mozart', 'Austrian composer (1756–1791). Musical genius from age 5. Over 600 compositions including ''Don Giovanni'' and ''The Magic Flute.'' Died at 35.', 'Compositor austríaco (1756–1791). Genio musical desde los 5 años. Más de 600 composiciones incluyendo ''Don Giovanni'' y ''La flauta mágica.'' Murió a los 35 años.'),
  ('bernadette_devlin', 'Bernadette Devlin', 'Irish civil rights leader (1947–). Youngest woman ever elected to Westminster. Fought for Catholic civil rights in Northern Ireland during the Troubles.', 'Líder de derechos civiles irlandesa (1947–). La mujer más joven en ser elegida para Westminster. Luchó por los derechos civiles católicos en Irlanda del Norte durante los Troubles.'),
  ('david_mccullough', 'David McCullough', 'American historian and author (1933–2022). Won two Pulitzer Prizes for ''Truman'' and ''John Adams.'' Made history narrative and accessible to all.', 'Historiador y autor estadounidense (1933–2022). Ganó dos Premios Pulitzer por ''Truman'' y ''John Adams.'' Hizo la historia narrativa y accesible para todos.'),
  ('jessamyn_west', 'Jessamyn West', 'American novelist (1902–1984). ''The Friendly Persuasion'' portrayed Quaker life during the Civil War. One of the first Hollywood films adapted by a woman.', 'Novelista estadounidense (1902–1984). ''La persuasión amistosa'' retrató la vida cuáquera durante la Guerra Civil. Una de las primeras películas de Hollywood adaptadas por una mujer.'),
  ('william_sloane_coffin', 'William Sloane Coffin', 'American minister and activist (1924–2006). Chaplain at Yale. Lifelong champion of civil rights, nuclear disarmament, and social justice.', 'Ministro y activista estadounidense (1924–2006). Capellán de Yale. Defensor de por vida de los derechos civiles y el desarme nuclear.'),
  ('joe_paterno', 'Joe Paterno', 'American football coach (1926–2012). Led Penn State for 46 years, winning more games than any coach in Division I history.', 'Entrenador de fútbol americano estadounidense (1926–2012). Dirigió Penn State durante 46 años ganando más partidos que cualquier otro entrenador de la División I.'),
  ('marian_wright_edelman', 'Marian Wright Edelman', 'American activist (1939–). Founded the Children''s Defense Fund. First Black woman admitted to the Mississippi Bar. ''The measure of a country''s greatness is how it treats its weakest members.''', 'Activista estadounidense (1939–). Fundó el Children''s Defense Fund. Primera mujer negra admitida en el Colegio de Abogados de Mississippi.'),
  ('maya_lin', 'Maya Lin', 'American architect and artist (1959–). Designed the Vietnam Veterans Memorial in Washington, D.C., at age 21. One of the most visited monuments in America.', 'Arquitecta y artista estadounidense (1959–). Diseñó el Monumento a los Veteranos de Vietnam en Washington D.C. a los 21 años. Uno de los monumentos más visitados de América.'),
  ('paulo_coelho', 'Paulo Coelho', 'Brazilian novelist (1947–). ''The Alchemist'' sold 150 million copies in 80 languages. Explores personal legends and spiritual journeys.', 'Novelista brasileño (1947–). ''El Alquimista'' vendió 150 millones de copias en 80 idiomas. Explora leyendas personales y viajes espirituales.'),
  ('thornton_wilder', 'Thornton Wilder', 'American playwright and novelist (1897–1975). ''Our Town'' won the Pulitzer. His works examined ordinary life with extraordinary depth.', 'Dramaturgo y novelista estadounidense (1897–1975). ''Nuestra ciudad'' ganó el Pulitzer. Sus obras examinaron la vida ordinaria con extraordinaria profundidad.'),
  ('william_burroughs', 'William Burroughs', 'American novelist (1914–1997). ''Naked Lunch'' challenged literary obscenity laws. Beat Generation icon who influenced punk rock and counterculture.', 'Novelista estadounidense (1914–1997). ''El almuerzo desnudo'' desafió las leyes de obscenidad literaria. Ícono de la Generación Beat que influyó en el punk rock.'),
  ('john_marshall', 'John Marshall', '4th Chief Justice of the U.S. (1755–1835). Established judicial review in ''Marbury v. Madison.'' His rulings defined the power of the Supreme Court.', '4.° Presidente del Tribunal Supremo de EE.UU. (1755–1835). Estableció la revisión judicial en ''Marbury contra Madison.'' Sus fallos definieron el poder del Tribunal Supremo.'),
  ('loretta_young', 'Loretta Young', 'American actress (1913–2000). Won Oscar for ''The Farmer''s Daughter.'' Known for elegance, faith, and longevity in Hollywood''s golden age.', 'Actriz estadounidense (1913–2000). Ganó el Óscar por ''La hija del granjero''. Conocida por su elegancia, fe y longevidad en la era dorada de Hollywood.'),
  ('pierre_auguste_renoir', 'Pierre-Auguste Renoir', 'French Impressionist painter (1841–1919). Famous for warm, vibrant depictions of people enjoying life. Continued painting even when arthritis forced him to strap brushes to his hands.', 'Pintor impresionista francés (1841–1919). Famoso por sus cálidas y vibrantes representaciones de personas disfrutando la vida. Siguió pintando aunque la artritis le obligó a atar los pinceles a las manos.'),
  ('billie_armstrong', 'Billie Armstrong', 'Likely Billie Joe Armstrong (1972–), American musician and co-founder of Green Day. Led punk rock''s mainstream breakthrough with ''Dookie'' and ''American Idiot.''', 'Billie Joe Armstrong (1972–), músico estadounidense y cofundador de Green Day. Lideró la irrupción del punk rock en el mainstream con ''Dookie'' y ''American Idiot.'''),
  ('david_eddings', 'David Eddings', 'American fantasy novelist (1931–2009). ''The Belgariad'' series introduced millions of readers to epic quest fantasy during the 1980s.', 'Novelista de fantasía estadounidense (1931–2009). La serie ''La Beldariada'' introdujo a millones de lectores en la fantasía épica de búsqueda durante los años 80.'),
  ('henry_wadsworth_longfellow', 'Henry Wadsworth Longfellow', 'American poet (1807–1882). ''Paul Revere''s Ride'' and ''The Song of Hiawatha.'' The most widely read American poet of the 19th century.', 'Poeta estadounidense (1807–1882). ''La cabalgata de Paul Revere'' y ''El canto de Hiawatha.'' El poeta americano más leído del siglo XIX.'),
  ('katherine_mansfield', 'Katherine Mansfield', 'New Zealand short story writer (1888–1923). Pioneered the modernist short story alongside Chekhov and Joyce. Died of tuberculosis at 34.', 'Escritora de cuentos neozelandesa (1888–1923). Pionera del cuento modernista junto a Chéjov y Joyce. Murió de tuberculosis a los 34 años.'),
  ('s_ren_kierkegaard', 'Søren Kierkegaard', 'Danish philosopher (1813–1855), father of existentialism. ''Fear and Trembling'' and ''Either/Or'' explored anxiety, despair, and the leap of faith.', 'Filósofo danés (1813–1855), padre del existencialismo. ''Temor y temblor'' exploró la angustia y el salto de fe.'),
  ('theodore_h_white', 'Theodore H. White', 'American journalist and author (1915–1986). ''The Making of the President 1960'' invented the genre of inside political reporting.', 'Periodista y autor estadounidense (1915–1986). ''La conquista de la presidencia 1960'' inventó el género del reportaje político de interior.'),
  ('william_hazlitt', 'William Hazlitt', 'English essayist and critic (1778–1830). Champion of the Romantic poets. His personal essays on art, theater, and ideas have never been surpassed.', 'Ensayista y crítico inglés (1778–1830). Defensor de los poetas románticos. Sus ensayos personales sobre arte, teatro e ideas no han sido superados.'),
  ('walt_disney', 'Walt Disney', 'American animator and entrepreneur (1901–1966). Created Mickey Mouse, Disneyland, and a media empire. Won 22 Academy Awards — a record.', 'Animador y empresario estadounidense (1901–1966). Creó a Mickey Mouse, Disneylandia y un imperio mediático. Ganó 22 premios Óscar — un récord.'),
  ('mortimer_j_adler', 'Mortimer J. Adler', 'American philosopher and educator (1902–2001). Editor of ''Great Books of the Western World.'' Championed classical liberal education for all.', 'Filósofo y educador estadounidense (1902–2001). Editor de ''Los grandes libros del mundo occidental.'' Defensor de la educación liberal clásica para todos.'),
  ('colette', 'Colette', 'French novelist (1873–1954). ''Gigi'', ''Claudine.'' Wrote frankly and beautifully about female desire and independence. First woman president of the Académie Goncourt.', 'Novelista francesa (1873–1954). ''Gigi'', ''Claudina.'' Escribió con franqueza y belleza sobre el deseo femenino y la independencia. Primera presidenta femenina de la Academia Goncourt.'),
  ('etty_hillesum', 'Etty Hillesum', 'Dutch diarist (1914–1943). Her journals from Nazi-occupied Amsterdam, published posthumously, reveal a mind seeking transcendence while surrounded by horror.', 'Diarista holandesa (1914–1943). Sus diarios desde la Amsterdam ocupada por los nazis, publicados póstumamente, revelan una mente que busca la trascendencia rodeada de horror.'),
  ('john_junor', 'John Junor', 'Scottish journalist (1919–1997). Editor of the Sunday Express for 32 years. His column ''JJ'' was sharp, patriotic, and wildly popular.', 'Periodista escocés (1919–1997). Editor del Sunday Express durante 32 años. Su columna ''JJ'' fue incisiva, patriótica y enormemente popular.'),
  ('ralph_marston', 'Ralph Marston', 'American motivational writer and creator of The Daily Motivator, a widely read source of daily inspiration.', 'Escritor motivacional estadounidense y creador de The Daily Motivator, una ampliamente leída fuente de inspiración diaria.'),
  ('anne_lamott', 'Anne Lamott', 'American novelist and nonfiction author (1954–). ''Bird by Bird'' is the most beloved writing guide of its generation. Writes with piercing honesty about faith and mess.', 'Novelista y autora de no ficción estadounidense (1954–). ''Pájaro a pájaro'' es la guía de escritura más querida de su generación. Escribe con honestidad penetrante sobre la fe.'),
  ('anne_lindbergh', 'Anne Lindbergh', 'American author (1906–2001), wife of Charles Lindbergh. ''Gift from the Sea'' — a meditation on solitude, simplicity, and women''s inner life — sold millions.', 'Autora estadounidense (1906–2001), esposa de Charles Lindbergh. ''Regalo del mar'' — una meditación sobre la soledad y la vida interior femenina — vendió millones.'),
  ('charles_darwin', 'Charles Darwin', 'English naturalist (1809–1882). ''On the Origin of Species'' established evolution by natural selection. Changed humanity''s understanding of life itself.', 'Naturalista inglés (1809–1882). ''El origen de las especies'' estableció la evolución por selección natural. Cambió la comprensión de la humanidad sobre la vida misma.'),
  ('francis_bacon', 'Francis Bacon', 'English philosopher and statesman (1561–1626). Father of the scientific method. ''Knowledge is power.'' Lord Chancellor of England.', 'Filósofo y estadista inglés (1561–1626). Padre del método científico. ''El conocimiento es poder.'' Lord Canciller de Inglaterra.'),
  ('george_washington', 'George Washington', '1st U.S. President (1732–1799). Commander of the Continental Army. Voluntarily relinquished power after two terms, setting a democratic precedent.', '1.er Presidente de EE.UU. (1732–1799). Comandante del Ejército Continental. Renunció voluntariamente al poder tras dos mandatos, sentando un precedente democrático.'),
  ('janis_joplin', 'Janis Joplin', 'American singer (1943–1970). Raw, bluesy voice. ''Me and Bobby McGee'', ''Piece of My Heart.'' Died at 27, but her impact on rock music is permanent.', 'Cantante estadounidense (1943–1970). Voz cruda y blues. ''Me and Bobby McGee'', ''Piece of My Heart.'' Murió a los 27 años, pero su impacto en el rock es permanente.'),
  ('j_willard_marriott', 'J. Willard Marriott', 'American hotelier (1900–1985). Founded what became Marriott International from a root beer stand. Built one of the world''s largest hospitality companies.', 'Hotelero estadounidense (1900–1985). Fundó lo que se convertiría en Marriott International desde un puesto de cerveza de raíz. Construyó una de las mayores empresas de hostelería del mundo.'),
  ('jane_addams', 'Jane Addams', 'American social reformer (1860–1935). Founded Hull House in Chicago, pioneering settlement house work. Nobel Peace Prize 1931. First American woman to win it.', 'Reformadora social estadounidense (1860–1935). Fundó Hull House en Chicago. Premio Nobel de la Paz en 1931. Primera mujer americana en recibirlo.'),
  ('margaret_mead', 'Margaret Mead', 'American anthropologist (1901–1978). ''Coming of Age in Samoa.'' Her work on cultural norms challenged Western assumptions about human behavior.', 'Antropóloga estadounidense (1901–1978). ''Adolescencia, sexo y cultura en Samoa.'' Su trabajo sobre normas culturales desafió los supuestos occidentales sobre el comportamiento humano.'),
  ('peter_abelard', 'Peter Abelard', 'French philosopher and theologian (1079–1142). Famous for his tragic love affair with Héloïse. His method of ''Sic et Non'' (Yes and No) pioneered scholastic debate.', 'Filósofo y teólogo francés (1079–1142). Famoso por su trágico amor con Eloísa. Su método ''Sic et Non'' (Sí y No) fue pionero del debate escolástico.'),
  ('richard_whately', 'Richard Whately', 'English logician and theologian (1787–1863). Archbishop of Dublin. His ''Elements of Logic'' revived formal logic in English-speaking universities.', 'Lógico y teólogo inglés (1787–1863). Arzobispo de Dublín. Sus ''Elementos de lógica'' revivieron la lógica formal en las universidades de habla inglesa.'),
  ('vaclav_havel', 'Václav Havel', 'Czech playwright and president (1936–2011). Led the Velvet Revolution that ended communism in Czechoslovakia. Became president through moral authority, not force.', 'Dramaturgo y presidente checo (1936–2011). Lideró la Revolución de Terciopelo que acabó con el comunismo en Checoslovaquia. Llegó a la presidencia por autoridad moral.'),
  ('walter_inglis_anderson', 'Walter Inglis Anderson', 'American artist (1903–1965). Rowed alone to a barrier island to paint wildlife in isolation. His murals and diaries were discovered after his death.', 'Artista estadounidense (1903–1965). Remaba solo hasta una isla costera para pintar la vida salvaje en soledad. Sus murales y diarios fueron descubiertos tras su muerte.'),
  ('alexis_carrel', 'Alexis Carrel', 'French surgeon and biologist (1873–1944). Nobel Prize for vascular suturing techniques. His work enabled organ transplants. Also a controversial eugenicist.', 'Cirujano y biólogo francés (1873–1944). Premio Nobel por técnicas de sutura vascular. Su trabajo permitió los trasplantes de órganos.'),
  ('doug_larson', 'Doug Larson', 'American newspaper columnist whose witty, ironic one-liners have been widely anthologized. Champion of the perfectly turned phrase.', 'Columnista de periódico estadounidense cuyos ingeniosos e irónicos epigramas han sido ampliamente antologizados.'),
  ('rita_mae_brown', 'Rita Mae Brown', 'American novelist (1944–). ''Rubyfruit Jungle'' was a landmark novel of lesbian identity and liberation. Also writes mystery novels with her cat Sneaky Pie Brown.', 'Novelista estadounidense (1944–). ''Rubyfruit Jungle'' fue una novela pionera de identidad lésbica y liberación.'),
  ('george_sand', 'George Sand', 'French novelist (1804–1876), born Amantine Dupin. Wore men''s clothing and smoked cigars. ''Indiana'' and ''Consuelo.'' Had famous affairs with Chopin and Musset.', 'Novelista francesa (1804–1876), nacida Amantine Dupin. Usó ropa de hombre y fumaba puros. ''Indiana'' y ''Consuelo.'' Tuvo amores famosos con Chopin y Musset.'),
  ('louisa_may_alcott', 'Louisa May Alcott', 'American novelist (1832–1888). ''Little Women'' drew from her own New England upbringing. One of America''s first feminist heroines.', 'Novelista estadounidense (1832–1888). ''Mujercitas'' bebió de su propia crianza en Nueva Inglaterra. Una de las primeras heroínas feministas de América.'),
  ('moncure_d_conway', 'Moncure D. Conway', 'American abolitionist and author (1832–1907). Minister who abandoned his slaveholding background to champion Emerson''s ideals and abolitionism.', 'Abolicionista y autor estadounidense (1832–1907). Ministro que abandonó sus raíces esclavistas para defender los ideales de Emerson y el abolicionismo.'),
  ('uta_hagen', 'Uta Hagen', 'German-American actress and teacher (1919–2004). Star of Broadway for 60 years. Her book ''Respect for Acting'' remains the bible of American theater training.', 'Actriz y profesora alemana-estadounidense (1919–2004). Estrella de Broadway durante 60 años. Su libro ''Respeto por la actuación'' sigue siendo la biblia de la formación teatral americana.'),
  ('william_butler_yeats', 'William Butler Yeats', 'Irish poet and Nobel laureate (1865–1939). Central figure of the Irish Literary Revival. ''The Second Coming'' remains one of the most quoted poems.', 'Poeta y Nobel irlandés (1865–1939). Figura central del Renacimiento Literario Irlandés. ''La segunda venida'' sigue siendo uno de los poemas más citados en inglés.'),
  ('booker_t_washington', 'Booker T. Washington', 'American educator (1856–1915). Born into slavery, founded Tuskegee Institute. Advocated for Black economic self-reliance and education.', 'Educador estadounidense (1856–1915). Nacido en la esclavitud, fundó el Instituto Tuskegee. Abogó por la autosuficiencia económica y la educación de los afroamericanos.'),
  ('walt_whitman', 'Walt Whitman', 'American poet (1819–1892). ''Leaves of Grass'' celebrated democracy, nature, and the human body. Called ''the father of free verse.''', 'Poeta estadounidense (1819–1892). ''Hojas de hierba'' celebró la democracia, la naturaleza y el cuerpo humano. Llamado ''el padre del verso libre.'''),
  ('arthur_conan_doyle', 'Arthur Conan Doyle', 'British writer (1859–1930). Created Sherlock Holmes, the most famous fictional detective. Also a physician, sportsman, and spiritualist.', 'Escritor británico (1859–1930). Creó a Sherlock Holmes, el detective ficticio más famoso. También fue médico, deportista y espiritualista.'),
  ('ellen_gilchrist', 'Ellen Gilchrist', 'American novelist and short story writer (1935–). National Book Award winner for ''Victory Over Japan.'' Writes with wit and grit about Southern women.', 'Novelista y cuentista estadounidense (1935–). Premio Nacional del Libro por ''Victoria sobre Japón.'' Escribe con ingenio y fuerza sobre las mujeres del Sur.'),
  ('judy_garland', 'Judy Garland', 'American actress and singer (1922–1969). Dorothy in ''The Wizard of Oz.'' Her turbulent life and electrifying talent made her an enduring cultural icon.', 'Actriz y cantante estadounidense (1922–1969). Dorothy en ''El mago de Oz.'' Su vida turbulenta y su talento electrizante la convirtieron en un icono cultural perdurable.'),
  ('sigmund_freud', 'Sigmund Freud', 'Austrian neurologist (1856–1939). Founded psychoanalysis. Introduced the unconscious mind, the id/ego/superego, and dream interpretation to modern thought.', 'Neurólogo austríaco (1856–1939). Fundó el psicoanálisis. Introdujo el inconsciente, el id/ego/superyó y la interpretación de los sueños en el pensamiento moderno.'),
  ('w_h_auden', 'W. H. Auden', 'British-American poet (1907–1973). ''Funeral Blues'', ''Musée des Beaux Arts.'' His formal mastery and political engagement made him the defining poet of the 1930s.', 'Poeta británico-estadounidense (1907–1973). ''Funeral Blues'', ''Musée des Beaux Arts.'' Su maestría formal y compromiso político lo convirtieron en el poeta definitorio de los años 30.'),
  ('a_powell_davies', 'A. Powell Davies', 'American minister (1902–1957). Unitarian preacher at All Souls Church in Washington D.C. Known for sermons connecting liberal religion to social justice.', 'Ministro estadounidense (1902–1957). Predicador unitario en Washington D.C. Conocido por sermones que vinculaban la religión liberal con la justicia social.'),
  ('john_powell', 'John Powell', 'British composer (1963–). Oscar-nominated film composer. Scored ''How to Train Your Dragon'', ''Bourne Identity'', and many others.', 'Compositor británico (1963–). Nominado al Óscar. Compuso ''Cómo entrenar a tu dragón'', ''La identidad Bourne'' y muchas otras bandas sonoras.'),
  ('michael_korda', 'Michael Korda', 'British-American author and editor (1933–). Former editor-in-chief of Simon & Schuster. Wrote bestselling biographies of Eisenhower, Grant, and T. E. Lawrence.', 'Autor y editor británico-estadounidense (1933–). Ex editor en jefe de Simon & Schuster. Escribió exitosas biografías de Eisenhower, Grant y T. E. Lawrence.'),
  ('sam_keen', 'Sam Keen', 'American philosopher (1931–). Longtime contributing editor to Psychology Today. ''Fire in the Belly'' examined modern masculinity and spiritual quest.', 'Filósofo y autor estadounidense (1931–). ''Fuego en el vientre'' examinó la masculinidad moderna y la búsqueda espiritual.'),
  ('paavo_nurmi', 'Paavo Nurmi', 'Finnish distance runner (1897–1973). ''The Flying Finn.'' Won nine Olympic gold medals. Ran with a stopwatch to pace himself precisely.', 'Corredor de fondo finlandés (1897–1973). ''El Finlandés Volador.'' Ganó nueve medallas de oro olímpicas. Corría con cronómetro para marcarse el ritmo con precisión.'),
  ('richard_garriott', 'Richard Garriott', 'American video game designer (1961–). Created the ''Ultima'' series and coined the term ''avatar.'' Second-generation astronaut; his father was an astronaut too.', 'Diseñador de videojuegos estadounidense (1961–). Creó la serie ''Ultima'' y acuñó el término ''avatar.'' Astronauta de segunda generación.'),
  ('charlotte_bronte', 'Charlotte Brontë', 'English novelist (1816–1855). ''Jane Eyre'' — a revolutionary portrayal of a woman''s inner life. Published under the name Currer Bell to bypass gender prejudice.', 'Novelista inglesa (1816–1855). ''Jane Eyre'' — un retrato revolucionario de la vida interior de una mujer. Publicó bajo el nombre de Currer Bell para sortear los prejuicios de género.'),
  ('elizabeth_browning', 'Elizabeth Browning', 'Elizabeth Barrett Browning (1806–1861). Victorian poet. ''How do I love thee? Let me count the ways.'' One of the most acclaimed poets of the 19th century.', 'Elizabeth Barrett Browning (1806–1861). Poetisa victoriana. ''¿Cómo te amo? Déjame contar las formas.'' Una de las poetisas más aclamadas del siglo XIX.'),
  ('james_oppenheim', 'James Oppenheim', 'American poet and novelist (1882–1932). Founding editor of The Seven Arts magazine. His poems on consciousness and the soul influenced a generation.', 'Poeta y novelista estadounidense (1882–1932). Editor fundador de la revista The Seven Arts. Sus poemas sobre la conciencia y el alma influyeron en toda una generación.'),
  ('dhammapada', 'Dhammapada', 'An anthology of the Buddha''s teachings compiled c. 3rd century BC. One of the most widely read and best-known texts of Theravada Buddhism.', 'Antología de las enseñanzas del Buda compilada c. siglo III a.C. Uno de los textos más leídos y conocidos del budismo Theravada.'),
  ('john_steinbeck', 'John Steinbeck', 'American novelist and Nobel laureate (1902–1968). ''The Grapes of Wrath'' and ''Of Mice and Men'' gave voice to America''s working poor.', 'Novelista y Nobel estadounidense (1902–1968). ''Las uvas de la ira'' y ''De ratones y hombres'' dieron voz a los trabajadores pobres de América.'),
  ('marcel_proust', 'Marcel Proust', 'French novelist (1871–1922). ''In Search of Lost Time'' — 7 volumes, 1.5 million words — is considered the greatest novel of the 20th century.', 'Novelista francés (1871–1922). ''En busca del tiempo perdido'' — 7 volúmenes, 1,5 millones de palabras — es considerada la mayor novela del siglo XX.'),
  ('muriel_rukeyser', 'Muriel Rukeyser', 'American poet and activist (1913–1980). Documented labor injustice and civil rights. ''The Book of the Dead'' was a pioneering work of documentary poetry.', 'Poetisa y activista estadounidense (1913–1980). Documentó la injusticia laboral y los derechos civiles. ''El libro de los muertos'' fue una obra pionera de poesía documental.'),
  ('robert_graves', 'Robert Graves', 'British poet and novelist (1895–1985). ''Goodbye to All That'' recounted WWI with brutal honesty. ''I, Claudius'' brought ancient Rome to life.', 'Poeta y novelista británico (1895–1985). ''Adiós a todo eso'' relató la Primera Guerra Mundial con brutal honestidad. ''Yo, Claudio'' dio vida a la Roma antigua.'),
  ('simone_weil', 'Simone Weil', 'French philosopher and mystic (1909–1943). Worked in factories to understand the working class. Her notebooks on suffering and grace remain deeply influential.', 'Filósofa y mística francesa (1909–1943). Trabajó en fábricas para entender a la clase obrera. Sus cuadernos sobre el sufrimiento y la gracia siguen siendo profundamente influyentes.'),
  ('alice_walker', 'Alice Walker', 'American novelist (1944–). ''The Color Purple'' won the Pulitzer Prize. Coined the term ''womanist'' for Black feminism.', 'Novelista estadounidense (1944–). ''El color púrpura'' ganó el Premio Pulitzer. Acuñó el término ''womanist'' para el feminismo negro.'),
  ('eknath_easwaran', 'Eknath Easwaran', 'Indian-American spiritual teacher (1910–1999). Taught meditation at Berkeley. His translations of the Bhagavad Gita and Upanishads are considered among the finest.', 'Maestro espiritual indo-americano (1910–1999). Enseñó meditación en Berkeley. Sus traducciones del Bhagavad Gita y las Upanishads se consideran entre las mejores.'),
  ('leo_buscaglia', 'Leo Buscaglia', 'American professor and author (1924–1998). ''Love'' and ''Living, Loving & Learning'' celebrated human connection. Known as ''Dr. Love'' for his bear hugs.', 'Profesor y autor estadounidense (1924–1998). ''Amor'' y ''Vivir, amar y aprender'' celebraron la conexión humana. Conocido como ''el Dr. Amor'' por sus abrazos de oso.'),
  ('mike_ditka', 'Mike Ditka', 'American football coach and player (1939–). Won Super Bowl XX as coach of the Chicago Bears. Known for intensity, directness, and Chicago stubbornness.', 'Entrenador y jugador de fútbol americano estadounidense (1939–). Ganó el Super Bowl XX como entrenador de los Chicago Bears. Conocido por su intensidad y franqueza.'),
  ('niccolo_machiavelli', 'Niccolò Machiavelli', 'Italian diplomat and philosopher (1469–1527). ''The Prince'' — a ruthlessly practical guide to political power — made his name synonymous with cunning.', 'Diplomático y filósofo italiano (1469–1527). ''El Príncipe'' — una guía despiadadamente práctica del poder político — hizo de su nombre sinónimo de astucia.'),
  ('charles_w_chesnutt', 'Charles W. Chesnutt', 'American novelist (1858–1932). First major African American fiction writer. ''The Marrow of Tradition'' exposed the racial violence of Reconstruction''s end.', 'Novelista estadounidense (1858–1932). Primer gran escritor de ficción afroamericano. ''El margen de la tradición'' expuso la violencia racial del fin de la Reconstrucción.'),
  ('john_acosta', 'John Acosta', 'Inspirational speaker and author known for motivational writing on resilience, purpose, and personal growth.', 'Orador inspiracional y autor conocido por escritos motivadores sobre la resiliencia, el propósito y el crecimiento personal.'),
  ('william_inge', 'William Inge', 'American playwright (1913–1973). ''Picnic'', ''Bus Stop'', ''Come Back, Little Sheba.'' Portrayed heartland American loneliness with quiet devastation.', 'Dramaturgo estadounidense (1913–1973). ''Picnic'', ''Bus Stop'', ''Vuelve, pequeña Sheba.'' Retrató la soledad de la América del interior con callada devastación.'),
  ('alexander_the_great', 'Alexander the Great', 'Macedonian king (356–323 BC). Conquered an empire stretching from Greece to India by age 30. Student of Aristotle. Never lost a battle.', 'Rey macedonio (356–323 a.C.). Conquistó un imperio que se extendía desde Grecia hasta India a los 30 años. Discípulo de Aristóteles. Nunca perdió una batalla.'),
  ('cheng_yen', 'Cheng Yen', 'Taiwanese Buddhist nun (1937–). Founded Tzu Chi Foundation — one of the world''s largest Buddhist humanitarian organizations.', 'Monja budista taiwanesa (1937–). Fundó Tzu Chi, una de las mayores organizaciones humanitarias budistas del mundo, con millones de voluntarios.'),
  ('john_pierrakos', 'John Pierrakos', 'American psychiatrist (1921–2001). Developed Core Energetics, a body-centered psychotherapy integrating Reichian bodywork with spiritual growth.', 'Psiquiatra estadounidense (1921–2001). Desarrolló la Energética del Núcleo, una psicoterapia centrada en el cuerpo que integra el trabajo corporal reichiano con el crecimiento espiritual.'),
  ('leon_blum', 'Léon Blum', 'French politician (1872–1950). First Socialist and first Jewish Prime Minister of France. Led the Popular Front government and survived Nazi imprisonment.', 'Político francés (1872–1950). Primer Ministro socialista y primer judío en liderar Francia. Sobrevivió el encarcelamiento nazi.'),
  ('nora_roberts', 'Nora Roberts', 'American romance novelist (1950–). World''s most prolific romance author — over 225 novels. First author inducted into the Romance Writers of America Hall of Fame.', 'Novelista de romance estadounidense (1950–). La autora de romance más prolífica del mundo — más de 225 novelas. Primera autora en el Salón de la Fama de la RWA.'),
  ('bo_jackson', 'Bo Jackson', 'American athlete (1962–). Only professional athlete named to both MLB and NFL All-Star games. The most complete athlete of his generation.', 'Atleta estadounidense (1962–). El único atleta profesional seleccionado para el All-Star Game de la MLB y la NFL. El atleta más completo de su generación.'),
  ('chuck_swindoll', 'Chuck Swindoll', 'American pastor and author (1934–). ''Life is 10% what happens to you and 90% how you react to it.'' Influential evangelical voice.', 'Pastor y autor estadounidense (1934–). ''La vida es 10% lo que te ocurre y 90% cómo reaccionas.'' Voz evangélica influyente.'),
  ('harriet_lerner', 'Harriet Lerner', 'American psychologist and author (1944–). ''The Dance of Anger'' sold millions. Pioneered understanding of women''s emotional lives within relationships.', 'Psicóloga y autora estadounidense (1944–). ''La danza de la ira'' vendió millones. Pionera en la comprensión de la vida emocional de las mujeres.'),
  ('iris_murdoch', 'Iris Murdoch', 'British-Irish philosopher and novelist (1919–1999). ''The Sea, The Sea'' won the Booker Prize. 26 novels exploring morality, love, and the unconscious.', 'Filósofa y novelista británica-irlandesa (1919–1999). ''El mar, el mar'' ganó el Booker Prize. 26 novelas que exploran la moralidad, el amor y el inconsciente.'),
  ('philip_sidney', 'Philip Sidney', 'English poet, courtier, and soldier (1554–1586). ''Astrophel and Stella'' began the English sonnet tradition. Died in battle. Embodied the Renaissance ideal.', 'Poeta, cortesano y soldado inglés (1554–1586). ''Astrophel y Stella'' inició la tradición del soneto inglés. Murió en batalla. Encarnó el ideal renacentista.'),
  ('sri_chinmoy', 'Sri Chinmoy', 'Indian spiritual teacher (1931–2007). Founded centers for meditation worldwide. Known for extraordinary feats of physical strength as spiritual practice.', 'Maestro espiritual indio (1931–2007). Fundó centros de meditación en todo el mundo. Conocido por proezas físicas extraordinarias como práctica espiritual.'),
  ('amy_tan', 'Amy Tan', 'American novelist (1952–). ''The Joy Luck Club'' explored mother-daughter relationships across Chinese-American generations. Made into a landmark film.', 'Novelista estadounidense (1952–). ''El club de la buena estrella'' exploró las relaciones madre-hija entre generaciones chino-americanas.'),
  ('dr_seuss', 'Dr. Seuss', 'American children''s author (1904–1991), born Theodor Geisel. ''The Cat in the Hat'', ''Green Eggs and Ham.'' Taught millions of children to read through rhyme.', 'Autor de libros infantiles estadounidense (1904–1991), nacido Theodor Geisel. ''El gato con sombrero'', ''Huevos verdes y jamón.'' Enseñó a leer a millones de niños a través de la rima.'),
  ('hermann_hesse', 'Hermann Hesse', 'German-Swiss writer and Nobel laureate (1877–1962). ''Siddhartha'', ''Steppenwolf'', and ''The Glass Bead Game'' explored Eastern spirituality and self-discovery.', 'Escritor y Nobel alemán-suizo (1877–1962). ''Siddhartha'', ''El lobo estepario'' y ''El juego de abalorios'' exploraron la espiritualidad oriental y el autodescubrimiento.'),
  ('john_berry', 'John Berry', 'American journalist and author. Wrote widely on jazz music and business leadership.', 'Periodista y autor estadounidense. Escribió ampliamente sobre música jazz y liderazgo empresarial.'),
  ('lin_yutang', 'Lin Yutang', 'Chinese-American author (1895–1976). ''The Importance of Living'' introduced Chinese philosophy of leisurely enjoyment to Western readers.', 'Autor chino-americano (1895–1976). ''La importancia de vivir'' introdujo la filosofía china del disfrute tranquilo a los lectores occidentales.'),
  ('samuel_beckett', 'Samuel Beckett', 'Irish playwright and Nobel laureate (1906–1989). ''Waiting for Godot'' — where nothing happens, twice — defined absurdist theater.', 'Dramaturgo y Nobel irlandés (1906–1989). ''Esperando a Godot'' — donde no pasa nada, dos veces — definió el teatro del absurdo.'),
  ('charlotte_perkins_gilman', 'Charlotte Perkins Gilman', 'American sociologist and feminist (1860–1935). ''The Yellow Wallpaper'' portrayed postpartum confinement as a haunting horror story. Pioneered economic feminist theory.', 'Socióloga y feminista estadounidense (1860–1935). ''El papel pintado amarillo'' retrató el confinamiento posparto como una aterradora historia de terror. Pionera de la teoría feminista económica.'),
  ('e_e_cummings', 'E. E. Cummings', 'American poet (1894–1962). Radical typographic experiments and playful grammar. ''i carry your heart with me'' blended playfulness with deep emotion.', 'Poeta estadounidense (1894–1962). Experimentos tipográficos radicales. ''llevo tu corazón conmigo'' mezcló la jugabilidad con la emoción profunda.'),
  ('pericles', 'Pericles', 'Athenian statesman (495–429 BC). Led Athens during its Golden Age. Built the Parthenon. His funeral oration defined democratic ideals.', 'Estadista ateniense (495–429 a.C.). Lideró Atenas durante su Edad de Oro. Construyó el Partenón. Su oración fúnebre definió los ideales democráticos.'),
  ('carl_sagan', 'Carl Sagan', 'American astronomer (1934–1996). ''Cosmos'' brought the universe into living rooms. ''We are a way for the cosmos to know itself.''', 'Astrónomo estadounidense (1934–1996). ''Cosmos'' llevó el universo a los salones. ''Somos una forma que tiene el cosmos para conocerse a sí mismo.'''),
  ('chuck_norris', 'Chuck Norris', 'American martial artist and actor (1940–). Starred in ''Walker, Texas Ranger.'' His impossible feats became a beloved internet meme format.', 'Artista marcial y actor estadounidense (1940–). Protagonizó ''Walker, Texas Ranger.'' Sus hazañas imposibles se convirtieron en un popular formato de meme de internet.'),
  ('norman_cousins', 'Norman Cousins', 'American journalist (1915–1990). Editor of Saturday Review for 35 years. ''Anatomy of an Illness'' argued that humor and positive emotion are medical tools.', 'Periodista estadounidense (1915–1990). Editor de Saturday Review durante 35 años. ''Anatomía de una enfermedad'' argumentó que el humor y la emoción positiva son herramientas médicas.'),
  ('bodhidharma', 'Bodhidharma', 'Indian Buddhist monk (5th–6th century). Brought Chan (Zen) Buddhism to China. Legend says he meditated facing a wall for nine years.', 'Monje budista indio (siglos V–VI). Llevó el budismo Chan (Zen) a China. La leyenda dice que meditó mirando una pared durante nueve años.'),
  ('joan_didion', 'Joan Didion', 'American writer (1934–2021). ''Slouching Towards Bethlehem'' and ''The Year of Magical Thinking.'' Master of the personal essay and literary journalism.', 'Escritora estadounidense (1934–2021). ''Slouching Towards Bethlehem'' y ''El año del pensamiento mágico.'' Maestra del ensayo personal y el periodismo literario.'),
  ('mary_pickford', 'Mary Pickford', 'Canadian-American actress (1892–1979). ''America''s Sweetheart.'' Co-founded United Artists with Chaplin, Griffith, and Fairbanks. First Hollywood megastar.', 'Actriz canadiense-estadounidense (1892–1979). ''La novia de América.'' Cofundó United Artists con Chaplin, Griffith y Fairbanks. Primera gran superestrella de Hollywood.'),
  ('murray_gell_mann', 'Murray Gell-Mann', 'American physicist (1929–2019). Named the quark. Nobel Prize 1969. Called the quark from a James Joyce phrase — ''Three quarks for Muster Mark!''', 'Físico estadounidense (1929–2019). Nombró el quark. Premio Nobel en 1969. Tomó el nombre de un verso de James Joyce: ''¡Tres quarks para el Muster Mark!'''),
  ('arthur_schopenhauer', 'Arthur Schopenhauer', 'German philosopher (1788–1860). ''The World as Will and Representation.'' First Western philosopher to integrate Eastern thought. Influenced Nietzsche and Freud.', 'Filósofo alemán (1788–1860). ''El mundo como voluntad y representación.'' Primer filósofo occidental en integrar el pensamiento oriental. Influyó en Nietzsche y Freud.'),
  ('jimmy_dean', 'Jimmy Dean', 'American country singer and actor (1928–2010). ''Big Bad John'' was #1 for eight weeks. Founded Jimmy Dean Foods. Embodied American entrepreneurial spirit.', 'Cantante country y actor estadounidense (1928–2010). ''Big Bad John'' fue número 1 durante ocho semanas. Fundó Jimmy Dean Foods.'),
  ('ralph_abernathy', 'Ralph Abernathy', 'American civil rights leader (1926–1990). Closest ally of Martin Luther King Jr. Co-founded the Southern Christian Leadership Conference.', 'Líder de los derechos civiles estadounidense (1926–1990). El aliado más cercano de Martin Luther King Jr. Cofundó la Southern Christian Leadership Conference.'),
  ('amy_bloom', 'Amy Bloom', 'American novelist and psychotherapist (1953–). ''Away'' and ''Lucky Us.'' Her fiction combines psychological precision with emotional warmth.', 'Novelista y psicoterapeuta estadounidense (1953–). Su ficción combina precisión psicológica con calidez emocional.'),
  ('camillo_benso_count_of_cavour', 'Camillo Benso, Count of Cavour', 'Italian statesman (1810–1861). Architect of Italian unification. Used diplomacy, alliances, and cunning to forge modern Italy from fragmented states.', 'Estadista italiano (1810–1861). Arquitecto de la unificación italiana. Utilizó la diplomacia y la astucia para forjar la Italia moderna a partir de estados fragmentados.'),
  ('franz_liszt', 'Franz Liszt', 'Hungarian composer and pianist (1811–1886). The greatest piano virtuoso of the 19th century. Invented the solo recital format and modern conductor''s podium.', 'Compositor y pianista húngaro (1811–1886). El mayor virtuoso del piano del siglo XIX. Inventó el formato del recital en solitario y el podio del director moderno.'),
  ('henry_moore', 'Henry Moore', 'British sculptor (1898–1986). Known for large-scale abstract bronze figures with holes. One of the most recognized sculptors of the 20th century.', 'Escultor británico (1898–1986). Conocido por grandes figuras abstractas de bronce con agujeros. Uno de los escultores más reconocidos del siglo XX.'),
  ('maureen_dowd', 'Maureen Dowd', 'American journalist (1952–). Pulitzer Prize-winning op-ed columnist for The New York Times. Known for sharp political satire and pop culture references.', 'Periodista estadounidense (1952–). Columnista de opinión ganadora del Premio Pulitzer en The New York Times. Conocida por su sátira política y referencias a la cultura pop.'),
  ('satchel_paige', 'Satchel Paige', 'American baseball pitcher (c. 1906–1982). Legendary Negro Leagues star who entered the MLB at age 42. ''Don''t look back. Something might be gaining on you.''', 'Lanzador de béisbol estadounidense (c. 1906–1982). Estrella legendaria de las Ligas Negras que entró en la MLB a los 42 años. ''No mires atrás. Algo puede estar ganándote terreno.'''),
  ('anne_bradstreet', 'Anne Bradstreet', 'American Puritan poet (1612–1672). First published author in the American colonies. Her poetry navigated faith, loss, and womanhood in the New World.', 'Poetisa puritana estadounidense (1612–1672). Primera autora publicada en las colonias americanas. Su poesía navegó la fe, la pérdida y la feminidad en el Nuevo Mundo.'),
  ('henry_k_beecher', 'Henry K. Beecher', 'American anesthesiologist (1904–1976). First to rigorously study the placebo effect. ''The Powerful Placebo'' changed how clinical trials are conducted.', 'Anestesiólogo estadounidense (1904–1976). Primero en estudiar rigurosamente el efecto placebo. ''El poderoso placebo'' cambió la forma en que se realizan los ensayos clínicos.'),
  ('lewis_cass', 'Lewis Cass', 'American statesman and general (1782–1866). Governor of Michigan Territory, Secretary of State. Negotiated treaties with Native Americans, controversially.', 'Estadista y general estadounidense (1782–1866). Gobernador del Territorio de Michigan, Secretario de Estado. Negoció tratados con los nativos americanos.'),
  ('marsha_petrie_sue', 'Marsha Petrie Sue', 'American business author and speaker. Focuses on toxic workplace behaviors and communication strategies for professional women.', 'Autora empresarial y oradora estadounidense. Se centra en los comportamientos tóxicos en el lugar de trabajo y las estrategias de comunicación para mujeres profesionales.'),
  ('will_rogers', 'Will Rogers', 'American humorist (1879–1935). ''I never met a man I didn''t like.'' Actor, newspaper columnist, and America''s most beloved wit during the Depression.', 'Humorista estadounidense (1879–1935). ''Nunca conocí a un hombre que no me gustara.'' Actor, columnista y el ingenioso más querido de América durante la Depresión.'),
  ('reggie_jackson', 'Reggie Jackson', 'American baseball player (1946–). ''Mr. October.'' Three home runs in a single World Series game. Hall of Famer with the Yankees and A''s.', 'Jugador de béisbol estadounidense (1946–). ''Mr. Octubre.'' Tres jonrones en un solo juego de la Serie Mundial. Miembro del Salón de la Fama.')
