-- MindScrolling — Migration 010: Authors Table
-- Creates a first-class `authors` table and seeds all 432 known authors
-- with bilingual bios (EN + ES) sourced from author_bios.js.
-- SAFE to run on a live DB — uses IF NOT EXISTS and ON CONFLICT DO UPDATE.
-- Generated: 2026-03-18

-- ─── 1. Table ─────────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS authors (
  slug         VARCHAR(100) PRIMARY KEY,
  name         VARCHAR(200) NOT NULL,
  bio_en       TEXT,
  bio_es       TEXT,
  quote_count  INTEGER      NOT NULL DEFAULT 0,
  created_at   TIMESTAMPTZ  NOT NULL DEFAULT now(),
  updated_at   TIMESTAMPTZ  NOT NULL DEFAULT now()
);

-- ─── 2. Index ─────────────────────────────────────────────────────────────────

CREATE INDEX IF NOT EXISTS idx_authors_name
  ON authors(name);

-- ─── 3. RLS ───────────────────────────────────────────────────────────────────
-- Public read. No anon writes — all mutations go through Fastify service role.

ALTER TABLE authors ENABLE ROW LEVEL SECURITY;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_policies
    WHERE tablename = 'authors' AND policyname = 'authors_public_read'
  ) THEN
    CREATE POLICY authors_public_read
      ON authors
      FOR SELECT
      USING (true);
  END IF;
END;
$$;

-- ─── 4. updated_at trigger ────────────────────────────────────────────────────
-- Keeps updated_at current on any row update without application-layer code.

CREATE OR REPLACE FUNCTION set_updated_at()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_trigger
    WHERE tgname = 'trg_authors_updated_at'
  ) THEN
    CREATE TRIGGER trg_authors_updated_at
      BEFORE UPDATE ON authors
      FOR EACH ROW EXECUTE FUNCTION set_updated_at();
  END IF;
END;
$$;

-- ─── 5. Seed — 432 authors (EN + ES bios) ────────────────────────────────────
-- ON CONFLICT (slug) DO UPDATE keeps the seed idempotent:
--   re-running the migration will refresh bios without creating duplicates.
-- quote_count is intentionally left at 0 here; it is back-filled in section 6.

ON CONFLICT (slug) DO UPDATE
  SET
    name   = EXCLUDED.name,
    bio_en = EXCLUDED.bio_en,
    bio_es = EXCLUDED.bio_es;

-- ─── 6. Back-fill quote_count from quotes table ───────────────────────────────
-- Counts all quotes rows whose author column matches the author name.
-- Running this section multiple times is safe (it always overwrites).

UPDATE authors a
SET quote_count = (
  SELECT COUNT(*)
  FROM quotes q
  WHERE q.author = a.name
);
